insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:subject_to_subsection_6_where_an_accused_and_the_husband_or_wife_of_the_accused_', 'statute', 'Subject to subsection (6), where an accused and the husband or wife of the accused are standing trial together, neither spouse shall at the trial be competent to give evidence for the prosecution under subsection (1), or be compellable to give evidence under subsection (2) or (3). (6) Subsection (5) shall not apply to either spouse who is no longer liable to be convicted of any offence in the trial (whether as a result of pleading guilty or for any other reason). (7) Section 7 of the Evidence Ordinance (Cap. 8)', 'Subject to subsection (6), where an accused and the husband or wife of the accused are standing trial together, neither spouse shall at the trial be competent to give evidence for the prosecution under subsection (1), or be compellable to give evidence under subsection (2) or (3). (6) Subsection (5) shall not apply to either spouse who is no longer liable to be convicted of any offence in the trial (whether as a result of pleading guilty or for any other reason). (7) Section 7 of the Evidence Ordinance (Cap. 8) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "Subject to subsection (6), where an accused and the husband or wife of the accused are standing trial together, neither spouse shall at the trial be competent to give evidence for the prosecution under subsection (1), or be compellable to give evidence under subsection (2) or (3). (6) Subsection (5) shall not apply to either spouse who is no longer liable to be convicted of any offence in the trial (whether as a result of pleading guilty or for any other reason). (7) Section 7 of the Evidence Ordinance (Cap. 8)", "keywords": ["subsection", "trial", "evidence", "6)", "accused", "spouse"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.labe