insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:at_the_time_of_making_an_order_of_transfer_the_judge_may_remand_the_accused_pers', 'statute', 'At the time of making an order of transfer, the judge may remand the accused person in custody or on bail as he may consider appropriate. (11) Unless the judge otherwise orders in respect of any matter, an order of transfer shall operate to terminate the proceedings before the court. (12) An order of transfer shall not be subject to appeal. (13) This section shall not apply in relation to any proceedi ngs which stand transferred to the court pursuant to section 77A of the District Court Ordinance (Cap. 336)', 'At the time of making an order of transfer, the judge may remand the accused person in custody or on bail as he may consider appropriate. (11) Unless the judge otherwise orders in respect of any matter, an order of transfer shall operate to terminate the proceedings before the court. (12) An order of transfer shall not be subject to appeal. (13) This section shall not apply in relation to any proceedi ngs which stand transferred to the court pursuant to section 77A of the District Court Ordinance (Cap. 336) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "At the time of making an order of transfer, the judge may remand the accused person in custody or on bail as he may consider appropriate. (11) Unless the judge otherwise orders in respect of any matter, an order of transfer shall operate to terminate the proceedings before the court. (12) An order of transfer shall not be subject to appeal. (13) This section shall not apply in relation to any proceedi ngs which stand transferred to the court pursuant to section 77A of the District Court Ordinance (Cap. 336)", "keywords": ["order", "transfer", "shall", "judge", "time", "making"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
