insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:computation_of_sentences_of_imprisonment_1_the_length_of_any_sentence_of_impriso', 'statute', 'Computation of sentences of imprisonment (1) The length of any sentence of imprisonment imposed on a person by a court shall be treated as reduced by any period during which he was in custody by reason only of having been committed to custody by an order of a court made in connection with any proceedings relating to the sentence or the offence for which it was passed, or with any proceedings from which those proceedings arose, but where the person was, in respect of the offence for which the sentence of imprisonment was imposed, subject to an earlier order made under- (a) section 3 of the Probation of Offenders Ordinance (Cap. 298)', 'Computation of sentences of imprisonment (1) The length of any sentence of imprisonment imposed on a person by a court shall be treated as reduced by any period during which he was in custody by reason only of having been committed to custody by an order of a court made in connection with any proceedings relating to the sentence or the offence for which it was passed, or with any proceedings from which those proceedings arose, but where the person was, in respect of the offence for which the sentence of imprisonment was imposed, subject to an earlier order made under- (a) section 3 of the Probation of Offenders Ordinance (Cap. 298) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "Computation of sentences of imprisonment (1) The length of any sentence of imprisonment imposed on a person by a court shall be treated as reduced by any period during which he was in custody by reason only of having been committed to custody by an order of a court made in connection with any proceedings relating to the sentence or the offence for which it was passed, or with any proceedings from which those proceedings arose, but where the person was, in respect of the offence for which the sentence of imprisonment was imposed, subject to an earlier order made under- (a) section 3 of the Probation of Offenders Ordinance (Cap. 298)", "keywords": ["was", "imprisonment", "sentence", "proceedings", "imposed", "person"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
