insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:subject_to_subsection_2_of_this_section_where_an_appea_l_under_section_83m_is_al', 'statute', 'Subject to subsection (2) of this section, where an appea l under section 83M is allowed, the appellant may be tried accordingly for the offence with which he was charged, and the Court of Appeal may make such orders as appear to it to be necessary or expedient pending any such trial for his custody, admission to bail or continued detention under the Mental Health Ordinance (Cap. 136)', 'Subject to subsection (2) of this section, where an appea l under section 83M is allowed, the appellant may be tried accordingly for the offence with which he was charged, and the Court of Appeal may make such orders as appear to it to be necessary or expedient pending any such trial for his custody, admission to bail or continued detention under the Mental Health Ordinance (Cap. 136) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "Subject to subsection (2) of this section, where an appea l under section 83M is allowed, the appellant may be tried accordingly for the offence with which he was charged, and the Court of Appeal may make such orders as appear to it to be necessary or expedient pending any such trial for his custody, admission to bail or continued detention under the Mental Health Ordinance (Cap. 136)", "keywords": ["such", "subject", "subsection", "2)", "appea", "83m"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
