insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:any_sums_imposed_and_ordered_to_be_paid_by_a_parent_or_guardian_under_this_secti', 'statute', 'Any sums imposed and ordered to be paid by a parent or guardian under this section or on forfeiture of any such security as aforesaid, may be recovered from him by distress or imprisonment in like manner as if the order had been made on the conviction of the parent or guardian of the offence with which the child or young person was charged. (6) A parent or guardian may appeal against an order of a juven ile court under this section in manner prescribed by Part VII of the Magistrates Ordinance (Cap. 227)', 'Any sums imposed and ordered to be paid by a parent or guardian under this section or on forfeiture of any such security as aforesaid, may be recovered from him by distress or imprisonment in like manner as if the order had been made on the conviction of the parent or guardian of the offence with which the child or young person was charged. (6) A parent or guardian may appeal against an order of a juven ile court under this section in manner prescribed by Part VII of the Magistrates Ordinance (Cap. 227) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "Any sums imposed and ordered to be paid by a parent or guardian under this section or on forfeiture of any such security as aforesaid, may be recovered from him by distress or imprisonment in like manner as if the order had been made on the conviction of the parent or guardian of the offence with which the child or young person was charged. (6) A parent or guardian may appeal against an order of a juven ile court under this section in manner prescribed by Part VII of the Magistrates Ordinance (Cap. 227)", "keywords": ["parent", "guardian", "manner", "order", "sums", "imposed"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = exclude