insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:no_objection_shall_be_taken_to_any_information_or_complaint_to_which_the_accused', 'statute', 'No objection shall be taken to any information or complaint to which the accused has pleaded guilty, and the accused shall not afterwards be allowed to withdraw the plea except with the leave of a judge of the Court of First Instance. (Amended 25 of 1998 s. 2) (4) Where a judge grants leave to withdraw a plea of guilty in accordance with the provisions of subsection (3) he may, at the same time, exercise his powers under section 24A(1) of the Criminal Procedure Ordinance (Cap. 221)', 'No objection shall be taken to any information or complaint to which the accused has pleaded guilty, and the accused shall not afterwards be allowed to withdraw the plea except with the leave of a judge of the Court of First Instance. (Amended 25 of 1998 s. 2) (4) Where a judge grants leave to withdraw a plea of guilty in accordance with the provisions of subsection (3) he may, at the same time, exercise his powers under section 24A(1) of the Criminal Procedure Ordinance (Cap. 221) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "No objection shall be taken to any information or complaint to which the accused has pleaded guilty, and the accused shall not afterwards be allowed to withdraw the plea except with the leave of a judge of the Court of First Instance. (Amended 25 of 1998 s. 2) (4) Where a judge grants leave to withdraw a plea of guilty in accordance with the provisions of subsection (3) he may, at the same time, exercise his powers under section 24A(1) of the Criminal Procedure Ordinance (Cap. 221)", "keywords": ["shall", "accused", "guilty", "withdraw", "plea", "leave"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
