insert into casemap_documents (id, kind, label, document_text, metadata) values ('statute:possession_of_offensive_weapon_in_public_place_1_any_person_who_without_lawful_a', 'statute', 'Possession of Offensive Weapon in Public Place (1) Any person who, without lawful authority or reasonable excuse, has with him in any public place any offensive weapon shall be guilty of an offence and shall be sentenced, on summary conviction or conviction on indictment, in the manner specified in subsection (2). (2) A person convicted of an offence in subsection (1) shall- (a) if under the age of 14 years, be dealt with in accordance with the Juvenile Offenders Ordinance (Cap. 226)', 'Possession of Offensive Weapon in Public Place (1) Any person who, without lawful authority or reasonable excuse, has with him in any public place any offensive weapon shall be guilty of an offence and shall be sentenced, on summary conviction or conviction on indictment, in the manner specified in subsection (2). (2) A person convicted of an offence in subsection (1) shall- (a) if under the age of 14 years, be dealt with in accordance with the Juvenile Offenders Ordinance (Cap. 226) Hong Kong legislation discussed in criminal-law secondary sources.', '{"type": "statute", "label": "Possession of Offensive Weapon in Public Place (1) Any person who, without lawful authority or reasonable excuse, has with him in any public place any offensive weapon shall be guilty of an offence and shall be sentenced, on summary conviction or conviction on indictment, in the manner specified in subsection (2). (2) A person convicted of an offence in subsection (1) shall- (a) if under the age of 14 years, be dealt with in accordance with the Juvenile Offenders Ordinance (Cap. 226)", "keywords": ["offensive", "weapon", "public", "place", "1)", "person"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
