insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_w_ong_fung_kei', 'case', 'HKSAR v W ong Fung Kei', 'HKSAR v W ong Fung Kei of Hong Kong on Criminal Law (2nd Ed,) V ol 20, 2013 Reissue) at paras [130.010]-[130.023]. It was noted by the Court of Appeal that the obvious reason why a s 54(b) offence has no presumption attached to it in the way that a s 55 (below) offence has, is that to possess with the specific intent under s 54 can only sensibly mean that the prosecution must prove knowledge; a person cannot possess explosives with intent to endanger life or cause serious inj...', '{"type": "case", "label": "HKSAR v W ong Fung Kei", "keywords": ["hksar", "ong", "fung", "kei", "offence", "possess"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
