insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:dpp_for_northern_ireland_v_maxwell', 'case', 'DPP for Northern Ireland v Maxwell', 'DPP for Northern Ireland v Maxwell [54.06] Conspires It is unnecessary that an accomplice should have prior knowledge of the actual crime intended: see DPP for Northern Ireland v Maxwell [1978] 3 All ER 1140, (1978) 122 SJ 758 (HL). For the offence of conspiracy, see s 159A of the Crimes Ordinance (Cap 200). In essence, the prosecution must prove, in so far as actus reus is concerned, the existence of an agreement to do an unlawful act or a lawful act by unlawful means is required: R v C...', '{"type": "case", "label": "DPP for Northern Ireland v Maxwell", "keywords": ["dpp", "northern", "ireland", "maxwell", "intended", "see"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
