insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:court_of_appeal_in_england_in_r_v_hallam', 'case', 'Court of Appeal in England in R v Hallam', 'Court of Appeal in England in R v Hallam In the context of s 4(1) of the UK Explosive Substances Act 1983, the Court of Appeal in England in R v Hallam [1987] 1 QB 569, [1957] 1 All ER 665 (CA, Eng) held that not only must the defendant knowingly have pos session of the explosive substance, but he must also know that what he posse ssed was an explosive substance. However, the English provision conta ins the additional requirement of ‘knowingly’ having in his possession, which is absent in the...', '{"type": "case", "label": "Court of Appeal in England in R v Hallam", "keywords": ["explosive", "appeal", "england", "hallam", "knowingly", "substance"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
