insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_hallam', 'case', 'R v Hallam', 'R v Hallam The position in R v Hallam [1957] 1 QB 569, [1957] 1 All ER 665 (CA, Eng) that the requisite mens rea includes knowledge that the substance in his possession is in fact an explosive substance, is thus clearly not applicable in Hong Kong. [55.04] Knowingly Although the word ‘knowingly’ only qualifies the categorie s of persons in possession or having control of an explosive substance, knowledge that a substance is an explosive is required in relation to...', '{"type": "case", "label": "R v Hallam", "keywords": ["substance", "explosive", "hallam", "er", "ca", "eng)"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
