insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:po_koon_tai_and_others_v_the_queen', 'case', 'PO KOON TAI AND OTHERS v. THE QUEEN', 'PO KOON TAI AND OTHERS v. THE QUEEN Y et, as stated in Po Koon-tai & Ors v R [1980] HKLR 492, [1980] HKCU 40 (CA), s 89 of the Criminal Procedure Ordinance (Cap 221) does not create a separate statutory offence of aiding, abetting, counselin g or procuring, and the defendant shall be guilty of the same offence as his principal. That is in contrast with the present section, which seems to create a separate st atutory offence of aiding, abetting, counseling, or procuring, and the defendant...', '{"type": "case", "label": "PO KOON TAI AND OTHERS v. THE QUEEN", "keywords": ["offence", "po", "ordinance", "cap", "create", "separate"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
