insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_mccarthy', 'case', 'R v McCarthy', 'R v McCarthy In R v McCarthy (John Augustine)[1964] 1 All ER 95 (CA, Eng), the English Court of Appeal rejected the argument that it is logically impossible for someone to aid or abet in the mere possession of an explosive substance (contrary to the UK Explosive Substances Act 1883, s 4). Such an offence could be established where the defendant had knowledge of the principal’s possession or custody or control and was encouraging or in any way helping the principal t...', '{"type": "case", "label": "R v McCarthy", "keywords": ["possession", "mccarthy", "explosive", "principal", "custody", "control"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
