insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_same_criminal_act_in_hksar_v_kwai_ping_hung_anor', 'case', 'The Same Criminal Act In HKSAR v Kwai Ping Hung & Anor', 'The Same Criminal Act In HKSAR v Kwai Ping Hung & Anor [58.04] Common law This is defined in s 3 of the Interpretation and General Clauses Ordinance (Cap 1) as meaning the common law in force in Hong Kong. [58.05] The Same Criminal Act In HKSAR v Kwai Ping Hung & Anor [2007] 1 HKC 620, [2007] 4 HKLRD 451 (CA), the police found firearms, ammunitions and grenades in a locked suitcase in the sitting room of the defendant’s apartment. The defendants were charged with, inter alia, possession of firearms and ammu...', '{"type": "case", "label": "The Same Criminal Act In HKSAR v Kwai Ping Hung & Anor", "keywords": ["possession", "criminal", "act", "firearms", "same", "hksar"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
