insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_kwai_pui_hung_anor', 'case', 'HKSAR v Kwai Pui Hung & Anor', 'HKSAR v Kwai Pui Hung & Anor It would only be a breach of the present section if the defendants were charged under both offences for the possession of grenades alone. [58.06] General note For example, whilst a person cannot be punished twice for possession of the same item, the possession of different items within a suitcase can constitute separate acts of possession for charging purposes: see HKSAR v Kwai Pui Hung & Anor [2007] 1 HKC 620 (CA). 109 Crimes Ordinance (Cap 200) [58.06...', '{"type": "case", "label": "HKSAR v Kwai Pui Hung & Anor", "keywords": ["possession", "hksar", "kwai", "pui", "hung", "anor"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
