insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:s_j_v_wong_ka_yip_ken', 'case', 'S-J v Wong Ka Yip Ken', 'S-J v Wong Ka Yip Ken [59.07] Custody or control The Court of Final Appeal considered whether the custody or control had to be lawful in HKSAR v Wong Sui Ching (above), holding that property should not be treated as belonging to a person having custody or control of it only if the custody or control was lawful: per Ribeiro PJ. Further it was a pure question of fact - no law was involved: per Litton NPJ. [59.08] Computer Computer is not defined in this Part. In S-J v Wong Ka...', '{"type": "case", "label": "S-J v Wong Ka Yip Ken", "keywords": ["custody", "control", "computer", "wong", "was", "s-j"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
