insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_court_of_final_appeal_held_in_hksar_v_wong_sui_ching', 'case', 'The Court of Final Appeal held in HKSAR v Wong Sui Ching', 'The Court of Final Appeal held in HKSAR v Wong Sui Ching The Court of Final Appeal held in HKSAR v Wong Sui Ching [2012] 4 HKC 36 (CFA) that the extended meaning given to the phrase ‘propert y belonging to another’ under s 59(2) is not qualified by any requirement th at ‘custody or control’ must be lawful under the civil law. It is irrelevant that the offender might enjoy superior proprietary rights under the law of property. So long as another person had one of the proprietary interests referred to in sub-s...', '{"type": "case", "label": "The Court of Final Appeal held in HKSAR v Wong Sui Ching", "keywords": ["another", "property", "final", "appeal", "held", "hksar"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
