insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_steer', 'case', 'R v Steer', 'R v Steer Criminal Damage and Kindred Offences 301 2.1 The additional requirement: to endanger life [9-21] The additional requirement is fulfilled only if it can be proven that the defendant intended for life to be endangered as a result of the damage itself or was reckless as to the fact that life could be endangered. [9-22] In R v Steer, 25 the court held that the offence was not made out when a defendant shot a window behind which two people were standing. The...', '{"type": "case", "label": "R v Steer", "keywords": ["life", "was", "damage", "defendant", "steer", "additional"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
