insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:destroying_or_damaging_by_fire_see_r_v_denton', 'case', 'Destroying or damaging ... by fire See R v Denton', 'Destroying or damaging ... by fire See R v Denton The intention or recklessness as to endangering the life of another is relevant, rather than the extent of the actual damage occurred. In R v Dudley [1989] Crim LR 57 (CA, Eng), the defendant threw a firebomb at a house. Whilst t he house only sustained trivial damage due to fire extinguishment acts of the occupants therein, the defendant’s intention or recklessness was established since the firebomb could potentially cause much more damage to the house...', '{"type": "case", "label": "Destroying or damaging ... by fire See R v Denton", "keywords": ["see", "fire", "damage", "house", "below", "destroying"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
