insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:de_reneville_v_de_reneville', 'case', 'De Reneville v De Reneville', 'De Reneville v De Reneville [66.03] Wife or husband A void marriage is regarded as never having taken place, see i n particular De Reneville v De Reneville [1948] P 100, [1948] 1 All ER 56 (CA, Eng), per Lord Greene MR. On the other hand a voidable marriage is valid unless and until it had been annulled; see in particular De Reneville v De Reneville (above), and R v Algar [1954] 1 QB 279, [1953] 2 All ER 1381 (CA, Eng). [66.04] This Part ie, Pt VIII, ss 59-67 of the present Crimes...', '{"type": "case", "label": "De Reneville v De Reneville", "keywords": ["de", "reneville", "see", "marriage", "particular", "er"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
