insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_ra_hyun_137_crimes_ordinance', 'case', 'HKSAR v Ra Hyun 137 Crimes Ordinance', 'HKSAR v Ra Hyun 137 Crimes Ordinance For these purposes, a ‘disc’ embraces the concept of both the physical disc and the information stored in it: R v Governor of Brixton Prison ex p Levin [1996] 4 All ER 350, [1997] 1 Cr App Rep 335 (QB); affd R v Governor of Brixton Prison ex p Levin [1997] AC 741, [1997] 3 All ER 289 (HL). A car-parking label is capable of being an instrument and a false parking label comes within these provisions: R v Lau Wai-kuen [1996] HKCU 83(unreported, HCMA 945/19...', '{"type": "case", "label": "HKSAR v Ra Hyun 137 Crimes Ordinance", "keywords": ["hksar", "ra", "hyun", "crimes", "ordinance", "these"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
