insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chan_wing_hung', 'case', 'HKSAR v Chan Wing Hung', 'HKSAR v Chan Wing Hung The Court of Appeal in HKSAR v Chan Wing Hung [1997] 3 HKC 472 (CA) did not dispute this, but following R v Chapman [1959] 1 QB 100, [1958] 3 All ER 143 (CA, Eng), held it was not necessary to go any further than to hold that ‘unlawful’ means ‘illicit’ in the sense of intercourse outside the bounds of matrimony. Historically, a man could not be guilty as a principle in the first degree of rape upon his wife because the consent to mari tal intercourse im...', '{"type": "case", "label": "HKSAR v Chan Wing Hung", "keywords": ["hksar", "chan", "wing", "hung", "qb", "er"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
