insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_keita_ali', 'case', 'HKSAR v Keita Ali', 'HKSAR v Keita Ali In HKSAR v Keita Ali [2017] HKCU 647(unreported, CACC 419/2015, 14 February 2017) (CA), the Court of Appeal quashed a conviction for the offence of attempted rape on the basis that the trial judge had wrongly failed to leave an alternative offence of indecent assault against the complainant. The Court, applying Ho Hoi Shing v HKSAR [2008] 5 HKC 57, (2008) 11 HKCFAR 61, [2008] 5 HKLRD 658 (CFA) held that a judge has a duty to place before thejury all pos...', '{"type": "case", "label": "HKSAR v Keita Ali", "keywords": ["hksar", "offence", "buggery", "keita", "ali", "conviction"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
