insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:d_was_not_the_subject_matter_of_the_proceedings_in_leung_t_c_william_roy_v_s_j', 'case', 'D was not the subject matter of the proceedings in Leung T C William Roy v S-J', 'D was not the subject matter of the proceedings in Leung T C William Roy v S-J [118D.05] Constitutionality In relation to consensual sex, this section puts the minimum age limit for buggery between a man and a girl at 21 years of age. As for sexual intercourse between a man and a woman, the age limit is 16 years of age: see s 124 below. Section 118D was not the subject matter of the proceedings in Leung T C William Roy v S-J [2006] 4 HKLRD 211, [2006] HKCU 1585 (CA), and the court did not make a ruling on its constitutionality. Bu...', '{"type": "case", "label": "D was not the subject matter of the proceedings in Leung T C William Roy v S-J", "keywords": ["118d", "age", "constitutionality", "118c", "was", "subject"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
