insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_pak_kau', 'case', 'HKSAR v Wong Pak Kau', 'HKSAR v Wong Pak Kau [118L.04] Animal On what constitutes buggery with an animal, ie, bestiality, see R v Cozins (1834) 6 C & P 351; R v Brown (1889) 24 QBD 357; and R v Bourne (1952) 36 Cr App R 125. For a recent case, see HKSAR v Wong Pak Kau [2000] 2 HKC 310 (CFI). 118M. Abolition of buggery at common law The offence of buggery at common law is abolished. (Added 90 of 1991 s. 3) [118M.01] Enactment history This section was added pursuant to s 3 of the Crimes (Amendment)...', '{"type": "case", "label": "HKSAR v Wong Pak Kau", "keywords": ["118m", "buggery", "common", "see", "hksar", "wong"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
