insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:false_pretences_or_false_representations_it_was_held_in_r_v_dent', 'case', 'False pretences or false representations It was held in R v Dent', 'False pretences or false representations It was held in R v Dent The offence is not complete until intercourse has taken place: see R v Mackenzie & Higginson (1910) 75 JP 159. [120.04] False pretences or false representations It was held in R v Dent [1955] 2 QB 590, [1955] 2 All ER 806 (CA, Eng), that a statement of intention about future conduct cannot constitute a false pretence in criminal law. Subsection (2) therefore clarified the situation in Hong Kong. The representation does not require the sexual act or sexu...', '{"type": "case", "label": "False pretences or false representations It was held in R v Dent", "keywords": ["false", "pretences", "representations", "was", "held", "dent"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
