insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_ka_ki', 'case', 'HKSAR v Wong Ka Ki', 'HKSAR v Wong Ka Ki The prosecution must prove that the pretence or representation was false, and that such pretence or representation had procured another to do the unlawful sexual act, see: HKSAR v Wong Ka Ki [2013] 5 HKLRD 139, [2013] HKCU 2218 (CA). In that case it was held that the victim’s agreement to have se xual intercourse with the defendant had little or nothing to do with any belief in th e defendant’s pretence or representation, but everything to do with endin...', '{"type": "case", "label": "HKSAR v Wong Ka Ki", "keywords": ["defendant", "pretence", "representation", "was", "do", "hksar"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
