insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:lynch_v_dpp_for_northern_ireland', 'case', 'Lynch v DPP for Northern Ireland', 'Lynch v DPP for Northern Ireland However, there may be circumstances where the statutory context requires intention to be interpreted as requiring proof of a desire on the part of the accused to bring about the prohibited conduct or result: see Lynch v DPP for Northern Ireland [1975] AC 653, [1975] 1 All ER 913 (HL). In the absence of a requirement to interpret a statutory provision in that manner, and where, there remains a distinction between intention and desire, it is usually unnec...', '{"type": "case", "label": "Lynch v DPP for Northern Ireland", "keywords": ["intention", "ac", "hl)", "above)", "lynch", "dpp"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
