insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_so_wai_lun_was_delivered_before_the_recognition_of_intermediate_basesof_', 'case', 'HKSAR v So Wai Lun was delivered before the recognition of intermediate basesof liability in Kulemesin v HKSAR', 'HKSAR v So Wai Lun was delivered before the recognition of intermediate basesof liability in Kulemesin v HKSAR in view of the legislative histories of the offences of indec ent assault and unlawful sexual intercourse. The Court of Final Appeal’s affirmation of this decision ( So Wai Lun v HKSAR (2006) 9 HKCFAR 530, [2006] HKCU 1195 (CFA)) was also done without argument or scrutiny on this point. Further, HKSAR v So Wai Lun was delivered before the recognition of intermediate basesof liability in Kulemesin v HKSAR [2014] 1 HKC 1, (2013) 16 HKCFAR 195 (CFA). See s...', '{"type": "case", "label": "HKSAR v So Wai Lun was delivered before the recognition of intermediate basesof liability in Kulemesin v HKSAR", "keywords": ["hksar", "so", "wai", "lun", "was", "intercourse"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
