insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:so_wai_lun_v_hksar', 'case', 'So Wai Lun v HKSAR', 'So Wai Lun v HKSAR 4.3.1 Social condemnation [4-51] One example of a law that seeks to encourage social condemnation of a particular act is the strict liability incurred if a man has sexual intercourse with an underaged girl. In So Wai Lun v HKSAR, the Court of Final Appeal, in commenting on the subject, stated this:-93 The deterrent effect of the criminal law is not confined to deterring people from doing what they know is unlawful. It also encourages them to take care t...', '{"type": "case", "label": "So Wai Lun v HKSAR", "keywords": ["what", "unlawful", "so", "wai", "lun", "hksar"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
