insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_so_wai_lun', 'case', 'HKSAR v So Wai Lun', 'HKSAR v So Wai Lun However in two modern House of Lo rds authorities concerned with other age-based sexual offences ( B (A Minor) v DPP [2000] 2 AC 428 (QB) & R v K [2002] 1 AC 462 (HL)), it was held that the presumption of mens rea had not been rebutted and the precedential authority of Prince was confined to its facts. The submission that the s 124 offence was not a strict liability offence was however rejected in the Court of Appeal’s decision in HKSAR v So Wai Lun (ab...', '{"type": "case", "label": "HKSAR v So Wai Lun", "keywords": ["was", "offence", "hksar", "so", "wai", "lun"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
