insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chiu_kwok_ho', 'case', 'HKSAR v Chiu Kwok Ho', 'HKSAR v Chiu Kwok Ho [129.04] Prostitution Prostitution is proved if it is shown that a person offers his or her body commonly for lewdness for payment in return: see R v De Munck [1918] 1 KB 635 (CA, Eng). In R v Li Kin Wai [1985] 1 HKC 249 (CFI) it was held that the word ‘commonly’ was intended to mean ‘indiscriminately’ or ‘promiscuously’. [129.04] General note The section was designed to prohibit trafficking of persons to Hong Kong and was directed at participation in t...', '{"type": "case", "label": "HKSAR v Chiu Kwok Ho", "keywords": ["was", "hksar", "chiu", "kwok", "ho", "prostitution"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
