insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_court_considered_that_it_was_bound_by_the_authority_of_hksar_v_coady', 'case', 'The Court considered that it was bound by the authority of HKSAR v Coady', 'The Court considered that it was bound by the authority of HKSAR v Coady The Court considered that it was bound by the authority of HKSAR v Coady [2000] 3 HKC 570, [2000] 2 HKLRD 195 (CA), where it was held that the language and structure of Art 5(1) only provided for the fair operation of the law in relation to the arrest and detention of a person (per Keith JA). The applicant’s judicial review was accordingly dismissed. 138. (Repealed 90 of 1991 s. 16) [138.01] Enactment history This section was repealed by s 16 of the Cri...', '{"type": "case", "label": "The Court considered that it was bound by the authority of HKSAR v Coady", "keywords": ["was", "considered", "bound", "authority", "hksar", "coady"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
