insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_tse_hoipan_dominic', 'case', 'HKSAR v Tse Hoipan Dominic', 'HKSAR v Tse Hoipan Dominic Once the trial judge is satisfied the conditions of the section are fulfilled, he has no discretion, but is obliged t o permit the cross-examination: R v Lee Wing On (above). The judge may decide to permit limited cross-examination on particular aspects of the complainant’s prior sexual history which are considered relevant to issues in the trial: HKSAR v Tse Hoipan Dominic (above). The existence of other charges does not exclude this section, although...', '{"type": "case", "label": "HKSAR v Tse Hoipan Dominic", "keywords": ["cross-examination", "permit", "sexual", "other", "hksar", "tse"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
