insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:reasonable_expectation_of_privacy_in_r_v_jarvis', 'case', 'Reasonable expectation of privacy In R v Jarvis', 'Reasonable expectation of privacy In R v Jarvis The mental state required by the word is the accused’s intent tha t the individual subject not be aware that he/she is being observed or recorded. Therefore, in the instant case, even though the complainant had willingly posed nude in the live video chat with the accused, the conviction was upheld as the appellant intended the complainant not know he was taking screenshots of her. [159AAB.04] Reasonable expectation of privacy In R v Jarvis [2019] 1 SCR...', '{"type": "case", "label": "Reasonable expectation of privacy In R v Jarvis", "keywords": ["privacy", "was", "reasonable", "expectation", "jarvis", "accused"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
