insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:however_in_the_hong_kong_case_of_yip_chiu_cheung_v_r', 'case', 'However in the Hong Kong case of Yip Chiu-Cheung v R', 'However in the Hong Kong case of Yip Chiu-Cheung v R [159A.09] Intention of co-conspirators There is some uncertainty as to the required intention of co- conspirators. In Anderson (above), it was held that co-conspirators need only intend to play some part in the agreed course of conduct. However in the Hong Kong case of Yip Chiu-Cheung v R [1994] 2 HKCLR 35 (PC) at [39], it was held that it ‘is the intention to carry out the crime that constitutes the necessary mens rea for the offence’. It would seem th...', '{"type": "case", "label": "However in the Hong Kong case of Yip Chiu-Cheung v R", "keywords": ["yip", "chiu-cheung", "hong", "kong", "intention", "co-conspirators"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
