insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_krieger', 'case', 'HKSAR v Krieger', 'HKSAR v Krieger As the agreement was to carry out an unlawful act abroad, an indictment is not properly laid in this jurisdiction: see HKSAR v Krieger [2014] 3 HKLRD 404, [2013] HKCU 2898 (CA). The prosecution’s application for leave to appeal this to the Court of Final Appeal was dismissed, and the reasoning of the Court of Appeal was affirmed: see HKSAR v Lionel John Krieger [2014] HKCU 1851(unreported, FAMC 1/2014, 6 August 2014) (CFA). As the Court expressed (at pa...', '{"type": "case", "label": "HKSAR v Krieger", "keywords": ["was", "hksar", "krieger", "appeal", "out", "see"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
