insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:macau_is_not_indictable_in_hong_kong_see_also_hksar_v_wong_tak_keung', 'case', 'Macau is not indictable in Hong Kong... See also HKSAR v Wong Tak Keung', 'Macau is not indictable in Hong Kong... See also HKSAR v Wong Tak Keung By virtue of section 159A, aconspiracy to make such an offer in Macau is not indictable in Hong Kong... See also HKSAR v Wong Tak Keung [2015] 3 HKC 23, (2015) 18 HKCFAR 62 (CFA) which held that s 159A enacts the general common law lim iting extra-territorial jurisdiction in conspiracy cases. It provides that a conspiracy is justiciable in Hong Kong only if the agreed course of conduct involves committing a substantive offence which would be triable in...', '{"type": "case", "label": "Macau is not indictable in Hong Kong... See also HKSAR v Wong Tak Keung", "keywords": ["hong", "kong", "conspiracy", "offence", "159a", "macau"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
