insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_mak_chun_kong', 'case', 'HKSAR v Mak Chun Kong', 'HKSAR v Mak Chun Kong been sure that any of the other defendants were party to the conspiracy, the husband and wife could not be guilty as a matter of law. [159B.05] Under the age of criminal responsibility A person under the age of seven is conclusively presumed to be under the age of criminal responsibility: see the Juvenile Offenders Ordinance (Cap 226), s 3. [159B.06] Application to other offences of conspiracy See s 159E(6) below. See also HKSAR v Mak Chun Kong (above)...', '{"type": "case", "label": "HKSAR v Mak Chun Kong", "keywords": ["conspiracy", "age", "see", "hksar", "mak", "chun"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
