insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_mo_yuk_ping_anor', 'case', 'HKSAR v Mo Yuk Ping & Anor', 'HKSAR v Mo Yuk Ping & Anor The constitutional validity of the offence of conspiracy to defraud (ie, whether it is formulated with sufficient precision to be an offence ‘pr escribed by law’ as required by Art 39 of the Basic Law or ‘according to law’ as required by Art 11(1) of the Bill of Rights Ordinance) was considered in HKSAR v Mo Yuk Ping & Anor [2007] 1 HKC 255 (CA) and Mo Yuk Ping [2007] 4 HKC 107, [2007] 3 HKLRD 750 (CFA).', '{"type": "case", "label": "HKSAR v Mo Yuk Ping & Anor", "keywords": ["mo", "yuk", "ping", "hksar", "anor", "offence"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
