insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:s_j_v_wong_kwok_kau', 'case', 'S-J v Wong Kwok-Kau', 'S-J v Wong Kwok-Kau In response to the Court of Appeal’s comment in S-J v Wong Kwok-Kau [2004] 4 HKC 1, [2004] 3 HKLRD 208 (CA), s 101I of the Criminal Procedure Ordinance (Cap 221) was amended by the Statute Law (Miscellaneous Provisions) Ordinance 2008 (10 of 2008) to raise the maximum penalty for the offence of perverting the course of justice in 2008. With the introduction to the Legislation Publication Ordinance 2011 (13 of 2011), s 113C(5) of the Criminal Procedure O...', '{"type": "case", "label": "S-J v Wong Kwok-Kau", "keywords": ["ordinance", "cap", "s-j", "wong", "kwok-kau", "criminal"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
