insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_chi_fung', 'case', 'HKSAR v Wong Chi Fung', 'HKSAR v Wong Chi Fung Hong Kong is defined as the Hong Kong Special Administrative Region and the Hong Kong Special Administrative Region of the People’s Republic of China in s 3 of the Interpretation and General Clauses Ordinance (Cap 1). The geographical extent of Hong Kong is specified in Sch 2 to the Interpretation and General Clauses Ordinance (Cap 1). The geographical extent of Hong Kong can be further modified by statutory provisions like s 6 of the Guangzhou-Shenzhen...', '{"type": "case", "label": "HKSAR v Wong Chi Fung", "keywords": ["kong", "hong", "ordinance", "cap", "hksar", "wong"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
