insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:considering_the_suitability_see_r_v_harrow_justices', 'case', 'Considering the suitability See R v Harrow Justices', 'Considering the suitability See R v Harrow Justices [9D.06] Considering the suitability See R v Harrow Justices, ex p Morris [1973] QB 672, [1972] 3 All ER 494 (DC, Eng). [9D.07] Magistrate This is defined as meaning any person appointed to be a permanent or special magistrate under the Magistrates Ordinance (Cap 227) in s 3 of the Interpretation and General Clauses Ordinance (Cap 1). [9D.08] Definitions For the meaning of ‘court’, ‘admitted to bail’, ‘judge’ and ‘surrender to custody’, see s 9C above. 4...', '{"type": "case", "label": "Considering the suitability See R v Harrow Justices", "keywords": ["9d", "see", "considering", "suitability", "harrow", "justices"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
