insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_vu_thang_duong', 'case', 'HKSAR v Vu Thang Duong', 'HKSAR v Vu Thang Duong [9G.02] England Subsections (1)-(4) are to similar effect as paras 2, 9, 3 and 4 of Sch 1 to the UK Bail Act 1976 (c 63). [9G.03] ... there are substantial grounds for believing ... In HKSAR v Vu Thang Duong [2015] 3 HKC 293, [2015] 2 HKLRD 502 (CFI), Zervos J (as he then was) had the following comment on provisions of s 9G of Criminal Procedure Ordinance (Cap 221): The relevant provisions allow the court to take into account a range of relevant matters...', '{"type": "case", "label": "HKSAR v Vu Thang Duong", "keywords": ["bail", "9g", "hksar", "vu", "thang", "duong"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
