insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_fletcher', 'case', 'R v Fletcher', 'R v Fletcher As a matter of fundamental law, there is a presumption in favour of bail. The liberty of the subject is not some theoretical catchphra se. To lock someone up without sound reasons is entirely contrary to our system of law. [9G.04] Character, antecedents and previous convictions See R v Fletcher (1949) 113 JP 365; R v Armstrong [1951] 2 All ER 219, [1951] 2 TLR 36 (CA, Eng); Re Whitehouse [1951] 1 KB 673, [1951] 1 All ER 353 (DC, 425 Criminal Procedure O...', '{"type": "case", "label": "R v Fletcher", "keywords": ["fletcher", "9g", "er", "matter", "fundamental", "presumption"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
