insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:that_case_was_considered_in_r_v_raymond', 'case', 'That case was considered in R v Raymond', 'That case was considered in R v Raymond That case was considered in R v Raymond [1981] QB 910, [1981] 2 All ER 246 (CA, Eng) where it was held that the defendant had no right to be heard or make representations to a High Court judge on an application for leave to prefer a bill of indictment. However, in England the Court of Appeal has directed that in exceptional circumstances the judge may invite written submissions on behalf of any defendant affected if in his judgment, the interests of jus...', '{"type": "case", "label": "That case was considered in R v Raymond", "keywords": ["was", "judge", "ordinance", "case", "considered", "raymond"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
