insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:thus_in_r_v_morris', 'case', 'Thus in R v Morris', 'Thus in R v Morris offences which could not have been laid earlier become available. Thus in R v Morris (1867) LR 1 CCR 90, the accused had originally been convicted of assault. When the victim later died of injuries sustained in the assault, it was held that the earlier assault conviction did not bar a prosecution for murder or manslaughter. The accused bears the burden of proof in such a plea. The standard of proof is the civil standard: R v Coughlan and Young (1976) 63...', '{"type": "case", "label": "Thus in R v Morris", "keywords": ["assault", "ordinance", "cap", "thus", "morris", "earlier"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
