insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_choi_kwai_kun', 'case', 'HKSAR v Choi Kwai Kun', 'HKSAR v Choi Kwai Kun [57.05] Duty of the court to remind the defendant’s spouse when it is not compellable for him/her to testify for the prosecution? It is not a rule of law and a failure to do so may not amount to an irregularity, depending on the facts of the case. See discussions in HKSAR v Choi Kwai Kun [2006] HKCU 757(unreported, CACC 263/2005, 15 May 2006) (CA). 511 Criminal Procedure Ordinance (Cap 221) [57.05] bwpageid:: 511:: bwservice::::', '{"type": "case", "label": "HKSAR v Choi Kwai Kun", "keywords": ["hksar", "choi", "kwai", "kun", "duty", "remind"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
