insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:this_case_has_been_followed_in_r_v_man_ching_ip', 'case', 'This case has been followed in R v Man Ching Ip', 'This case has been followed in R v Man Ching Ip to be given Even if the jury believe the confession was improperly obtained, if they think it is true they may still rely on it: see R v Chan Wei Keung [1967] 2 AC 160 (PC). This case has been followed in R v Man Ching Ip [1980] HKC 25, [1980] HKLR 890 (CA) and R v Lee Ming [1990] 1 HKC 207 (CA). However, it has been held unwise for a trial judge to direct the jury that they could rely on the confession if they thought it was true even if it was made as...', '{"type": "case", "label": "This case has been followed in R v Man Ching Ip", "keywords": ["ca)", "man", "was", "hkc", "case", "followed"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
