insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:leung_kam_ting_v_hksar', 'case', 'Leung Kam-ting v HKSAR', 'Leung Kam-ting v HKSAR [79B.03] Witness in fear The critical issue in determining whether a witness can be ch aracterised as a ‘witness in fear’ is the state of mind of the witness. It is not necessary that their fears be objectively justified or that those fears are directly attributed to conduct on the part of the accused. See Leung Kam-ting v HKSAR [2009] 3 HKC 269, [2009] 3 HKLRD 476 (CA); R v Wong Kwai Nam (unreported, DCC 100053/95); R v Goldman [2004] VSC 165; Director...', '{"type": "case", "label": "Leung Kam-ting v HKSAR", "keywords": ["witness", "leung", "kam-ting", "hksar", "79b", "fear"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
