insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_see_wah_lun_and_ors', 'case', 'HKSAR v See Wah Lun and Ors', 'HKSAR v See Wah Lun and Ors VSC 303 and Bruce & McCoy, Criminal Evidence in Hong Kong (Butterworths Publications, 1987 Issue) at paras IX [553.3] and IX [553.4]. In deciding whether he is a witness in fear, the Court is to hav e regard to the circumstances of the case and the nature and circumstances o f the witness. Factors such as the witness being an accomplice and under a witness protection scheme may be taken into account: see HKSAR v See Wah Lun and Ors [2011] 2 HKLRD 957, [...', '{"type": "case", "label": "HKSAR v See Wah Lun and Ors", "keywords": ["witness", "see", "child", "hksar", "wah", "lun"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
