insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:chim_hon_man_v_hksar', 'case', 'Chim Hon Man v HKSAR', 'Chim Hon Man v HKSAR [79C.03] General note Leading questions are permissible: see R v Savage (No 1) [1996] 4 HKC 75 (DC), where a District Court judge held that the rationale behind the provision was to remove the interview from the realm of a formal court hearing and encourage a wider ranging and more sympathetic form of questioning of th e child witness. The strict rules of evidence could not be enforced at such an interview. If admitted, the video tape becomes a substitu...', '{"type": "case", "label": "Chim Hon Man v HKSAR", "keywords": ["evidence", "chim", "hon", "man", "hksar", "see"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
