insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_welstead', 'case', 'R v Welstead', 'R v Welstead As to whether the jury is entitled to a transcript of the video evidence of a complainant, see R v Coshall (1995) 159 JP 521 (CA, Eng). In R v Welstead [1996] 1 Cr App Rep 59 (CA, Eng), it was held that: the judge was entitled to allow the jury to have copies of the transcripts of the video recordings (by a child witness) whilst those recor dings were being played, provided: (1) that the transcripts would in fact be likely to assist them in following th...', '{"type": "case", "label": "R v Welstead", "keywords": ["jury", "evidence", "judge", "transcripts", "welstead", "entitled"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
