insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:nautham_v_hksar', 'case', 'Nautham v HKSAR', 'Nautham v HKSAR [83W.03] General note The Court of Final Appeal held in Chau Ching Kay, Nautham v HKSAR (2002) 5 HKCFAR 540, [2003] 1 HKLRD 99, [2002] HKCU 1415 (CFA) that the purpose of having the power to order loss of time was to deter unmeritorious applications. The result of wasting judicial time was that meritorious cases would have to be deferred or delayed, thus causing injustice to the parties in those cases, particularly where such parties are held in custody...', '{"type": "case", "label": "Nautham v HKSAR", "keywords": ["held", "nautham", "hksar", "83w", "appeal", "time"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
