insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_queen_v_chiu_hung_wong', 'case', 'The Queen v Chiu Hung Wong', 'The Queen v Chiu Hung Wong Trafficking in a dangerous drug is a serious offence, which attracts the maximum sentence of life imprisonment: s 4(3)(a) of the Ordinance. The Court of Appeal sets out various sentencing tariffs in respect of different kinds of dangerous drugs, as well as guidelines as to how to approach sentencing drug-trafficking offenders. The maximum sentence for simple possession of dangerous drug is seven years imprisonment: s 8(2)(a) of the Ordinance. The court...', '{"type": "case", "label": "The Queen v Chiu Hung Wong", "keywords": ["dangerous", "sentencing", "queen", "chiu", "hung", "wong"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
