insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:prior_to_the_judgment_of_the_queen_v_sin_yau_ming', 'case', 'Prior to the judgment of The Queen v Sin Yau Ming', 'Prior to the judgment of The Queen v Sin Yau Ming Prior to the judgment of The Queen v Sin Yau Ming [1992] 1 HKCLR 127, [1992] HKCU 373 (CA), under the original s 46(c) and (d) of the Ordina nce that anybody who was in possession of more than five packets containing dangerous drugs or more than 0.5 gram of dangerous drug is presumed to have possessed it for the purpose of trafficking. In R v Sin Y au Ming(above), it was held that such provision infringed Art 11(1) of the Hong Kong Bill of Rights Ordina...', '{"type": "case", "label": "Prior to the judgment of The Queen v Sin Yau Ming", "keywords": ["sin", "prior", "judgment", "queen", "yau", "ming"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
