insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:chan_man_ching_v_r', 'case', 'Chan Man Ching v R', 'Chan Man Ching v R [2.11] Dangerous drugs The trial judge is entitled to take judicial notice that ‘pak fan’ (white powder) is a term reserved for heroin in the form which is commonly used in Hong Kong: Chan Man Ching v R [1978] HKLR 97, [1978] HKCU 22 (CA). The judge can also take judicial notice of the fact that the average consumption of a heroin addict is between 0.25 and 0.7 gram of pure heroin a day; The Queen v Chan Kwok Kei 938 [2.05] Butterworths Hong Kong Crimin...', '{"type": "case", "label": "Chan Man Ching v R", "keywords": ["chan", "heroin", "man", "ching", "judge", "take"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
