insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_suet_hau_anor', 'case', 'HKSAR v Wong Suet Hau & Anor', 'HKSAR v Wong Suet Hau & Anor It was held in HKSAR v Chan Hong [1998] 2 HKC 688, [1995-2000] HKCLRT 147 (CA), that in respect of possession of a dangerous drug for the purpose of trafficking, the prosecution did not have to prove any act of dealing with the dangerous drug and that all they had to prove was that the defendant possessed the drug and had the intention and capability to make use of the whole or a part thereof for the purpose of trafficking. See also HKSAR v Wong Suet Ha...', '{"type": "case", "label": "HKSAR v Wong Suet Hau & Anor", "keywords": ["hksar", "drug", "wong", "suet", "hau", "anor"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
