insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chong_heung_sang', 'case', 'HKSAR v Chong Heung Sang', 'HKSAR v Chong Heung Sang As to ‘social trafficking’, it was held in S-J v Hii Siew Cheng [2008] 3 HKC 323, [2009] 1 HKLRD 1 (CA), that sharing dangerous drugs with friends constitutes trafficking, and the ‘social’ or ‘non-commercial’ nature of this kind of trafficking offences does not necessarily provide a basis for imposing a lighter sentence than would have been imposed for commercial trafficking. See also HKSAR v Chong Heung Sang [2010] 3 HKC 88 (CA). 3.', '{"type": "case", "label": "HKSAR v Chong Heung Sang", "keywords": ["trafficking", "hksar", "chong", "heung", "sang", "social"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
