insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:s_j_v_hii_siew_cheng', 'case', 'S-J v Hii Siew Cheng', 'S-J v Hii Siew Cheng As to ‘social trafficking’, it was held in S-J v Hii Siew Cheng [2008] 3 HKC 323, [2009] 1 HKLRD 1 (CA), that sharing dangerous drugs with friends constitutes trafficking, and the ‘social’ or ‘non-commercial’ nature of this kind of trafficking offences does not necessarily provide a basis for imposing a lighter sentence than would have been imposed for commercial trafficking. See also HKSAR v Chong Heung Sang [2010] 3 HKC 88 (CA). 3.', '{"type": "case", "label": "S-J v Hii Siew Cheng", "keywords": ["trafficking", "s-j", "hii", "siew", "cheng", "social"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
