insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:croxon_v_ferrers', 'case', 'Croxon v Ferrers', 'Croxon v Ferrers [16.06] Lawful manner There is no specific definition of ‘lawful manner’ under this Dangerous Drugs Ordinance (Cap 134); in Re Croxon, Croxon v Ferrers (1904) 73 LJ Ch 170, Kekewich J said at 172: it is extremely difficult to say exactly what the word ‘lawful’ means; I have referred to a dictionary, and according to that it really comes to this - that anything is lawful which is not forbidden by law ... but to mind ‘lawfully’ cannot be construed as not...', '{"type": "case", "label": "Croxon v Ferrers", "keywords": ["lawful", "croxon", "ferrers", "manner", "anything", "no"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
