insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:d_in_hksar_v_shing_siu_ming', 'case', 'D. In HKSAR v Shing Siu Ming', 'D. In HKSAR v Shing Siu Ming [38M.04] Knowing or having reasonable grounds to believe ‘Knowing’ means someone having knowledge of a fact or a certa in state of affairs. Examples of proof for the ‘knowing’ limb not only include evi dence by the offender’s admission that he had the required belief, but al so evidence of the person’s involvement in the offence: Seng Yuet Fong v HKSAR [1999] 2 HKC 833 (CFA) at 836D. In HKSAR v Shing Siu Ming [1999] 2 HKC 819 (CA), the first applicant w...', '{"type": "case", "label": "D. In HKSAR v Shing Siu Ming", "keywords": ["hksar", "knowing", "having", "shing", "siu", "ming"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
