insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:dpp_v_doot', 'case', 'DPP v Doot', 'DPP v Doot The offence of conspiracy cannot exist without t he agreement, consent or combination of two or more persons. See also: HKSAR v Lee Wai Ki & Ors [2001] 2 HKLRD 610, [2001] HKCU 582 (CFI). A conspiracy does not end with the making of the agreement, it continues so long as there are two or more parties to it intending to carry out the design: see DPP v Doot [1973] AC 807 (HL). 1047 Dangerous Drugs Ordinance (Cap 134) [39.01] bwpageid:: 1047:: bwservice::::', '{"type": "case", "label": "DPP v Doot", "keywords": ["dpp", "doot", "conspiracy", "agreement", "two", "more"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
