insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_lee_wai_ki_ors', 'case', 'HKSAR v Lee Wai Ki & Ors', 'HKSAR v Lee Wai Ki & Ors The offence of conspiracy cannot exist without t he agreement, consent or combination of two or more persons. See also: HKSAR v Lee Wai Ki & Ors [2001] 2 HKLRD 610, [2001] HKCU 582 (CFI). A conspiracy does not end with the making of the agreement, it continues so long as there are two or more parties to it intending to carry out the design: see DPP v Doot [1973] AC 807 (HL). 1047 Dangerous Drugs Ordinance (Cap 134) [39.01] bwpageid:: 1047:: bwservice::::', '{"type": "case", "label": "HKSAR v Lee Wai Ki & Ors", "keywords": ["hksar", "lee", "wai", "ki", "ors", "conspiracy"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
