insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_same_analysis_was_found_in_r_v_ng_chiu_leung', 'case', 'The same analysis was found in R v Ng Chiu Leung', 'The same analysis was found in R v Ng Chiu Leung This, of course, could only avail the accused if the dangerous drug that he thought he was trafficking in was one that the courts recognize as attracting a lesser sentence than the one stated in the particulars of offence. The same analysis was found in R v Ng Chiu Leung [1996] 1 HKC 181 (CA) at 187 where Patrick Chan J (as he then was) explained in even clearer terms: Reliance can be placed upon s 47(1) where a person has ‘physical possession’ of a con...', '{"type": "case", "label": "The same analysis was found in R v Ng Chiu Leung", "keywords": ["was", "he", "drug", "possession", "only", "dangerous"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
