insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_queen_v_pow_po_w_o', 'case', 'The Queen v Pow Po W o', 'The Queen v Pow Po W o In such cases, unless he proves the contrary, the presumption that he knew the nature of the drug stands. In the great majority of cases, the presumption in s 47(2) does not come into play as defendants normally contend that they did not know they had a dangerous drug at all. Much more common is the case where the defendant admits that he had possession of a container but states that he did not know that there was any dangerous drug therein (s 47(1)). H...', '{"type": "case", "label": "The Queen v Pow Po W o", "keywords": ["he", "dangerous", "drug", "was", "drugs", "queen"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
