insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:sentence_the_court_of_appeal_in_hksar_v_chan_ka_shing', 'case', 'Sentence The Court of Appeal in HKSAR v Chan Ka Shing', 'Sentence The Court of Appeal in HKSAR v Chan Ka Shing [56A.09] Sentence The Court of Appeal in HKSAR v Chan Ka Shing [2012] 2 HKLRD 220 held that as for the sentence enhancement by virtue of s 56A(2), it is not sufficient for the court to only consider the percentage of the enhancement, it should also consider the actual extent of the enhancement. It was stated at [30] that: This Court thinks the answer to the question is clear: Drug trafficking is of course a very serious offence; no offender should get o...', '{"type": "case", "label": "Sentence The Court of Appeal in HKSAR v Chan Ka Shing", "keywords": ["sentence", "enhancement", "appeal", "hksar", "chan", "ka"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
