insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:kau_yau_fung_v_a_g', 'case', 'Kau Yau Fung v A-G', 'Kau Yau Fung v A-G In construing the Births and Deaths Registration Ordinance (Cap 174), the Ful l Court held that ‘child’ meant a child who had not attained majority: see Kau Yau Fung v A-G [1969] HKLR 210 (FC). Under s 2(1) of the Age of Majority (Related Provisions) Ordinance (Cap 410), commencing on 1 October 1990, a person shall attain full age on attaining the age of 18 years as from the commencement o f that Ordinance. See also Halsbury’ s Laws of Hong Kong (2nd Ed...', '{"type": "case", "label": "Kau Yau Fung v A-G", "keywords": ["guardians", "ordinance", "age", "kau", "yau", "fung"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
