insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:court_of_appeal_in_hksar_v_yhn', 'case', 'Court of Appeal in HKSAR v YHN', 'Court of Appeal in HKSAR v YHN Regarding the extent of which the prosecution has to prove the child offender has guilty knowledge of criminal act or conduct, the Court of Appeal in HKSAR v YHN [2017] 1 HKLRD 686, [2015] HKCU 2973 (CA), observed that the child offender’s behavior and demeanour both before and after committing the offence is relevant to determine whether he was capable of committing the crime.', '{"type": "case", "label": "Court of Appeal in HKSAR v YHN", "keywords": ["appeal", "hksar", "yhn", "child", "offender", "committing"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
