insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chu_ka_1186', 'case', 'HKSAR v Chu Ka 1186', 'HKSAR v Chu Ka 1186 However, the court may refuse to remit the case to the juvenile court for sentence, if it satisfied that it would be undesirable to do so, for instance, where the court is of the view that it is more familiar with the case than the juvenile court which would put him in a better position in sentencing and remittin g the case to the juvenile court would potentially cause delay in sentencing as in HKSAR v Chu Ka 1186 [3F .01] Butterworths Hong Kong Crimina...', '{"type": "case", "label": "HKSAR v Chu Ka 1186", "keywords": ["case", "juvenile", "would", "hksar", "chu", "ka"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
