insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_law_ka_kit', 'case', 'HKSAR v Law Ka Kit', 'HKSAR v Law Ka Kit But also see: HKSAR v Law Ka Kit [2003] 2 HKC 178 (CA), where the Court of Appeal pointed out that the nature or prevalence of an offence may be such as t o demand an immediate custodial sentence despite the youth of the offender. Robbery has long been recognized as an offence within that category. See alsos 14(1)(a) below where the court may order the child to be detained in a place of detention. cf, A person of or over 16 and under 21 years of age sha...', '{"type": "case", "label": "HKSAR v Law Ka Kit", "keywords": ["hksar", "see", "ka", "kit", "hkc", "offence"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
