insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:wong_chun_cheong_v_hksar', 'case', 'Wong Chun Cheong v HKSAR', 'Wong Chun Cheong v HKSAR In Wong Chun Cheong v HKSAR [2001] 1 HKC 1, [2000] 3 HKLRD 840 (CFA) Ribeiro PJ summarised the proper approach of a court before making a training centre order as follows: (1) The court should first be satisfied that the threshold re quirements are met, ie, that the offence is punishable with imprisonment, and that the offence is punishable with imprisonment, and that the offender is aged between 14 and 21. (2) The court should then consider whether in...', '{"type": "case", "label": "Wong Chun Cheong v HKSAR", "keywords": ["should", "wong", "chun", "cheong", "hksar", "approach"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
