insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:scott_v_scott', 'case', 'Scott v Scott', 'Scott v Scott Sitting in camera is an exceptional step to take and should be avoided if there is other way of serving the interests of justice: see R v Malvern Justices, ex p Evans (above). The court would be justified in clearing the public from the court, for instance, where there was tumult or disorder, or the just apprehension of it: see Scott v Scott [1917] AC 417. See also the Hong Kong Bill of Rights Ordinance (Cap 383), Art10 which provides that ‘the public m...', '{"type": "case", "label": "Scott v Scott", "keywords": ["see", "scott", "meaning", "above", "public", "ordinance"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
