insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_hereford_magistrates', 'case', 'R v Hereford Magistrates', 'R v Hereford Magistrates Criminal Law in Hong Kong 30 [1-102] In exercising appellate jurisdiction, a Court of First Instance Judge would hear a magistracy appeal sitting alone. Unlike appeals to the Court of Appeal or the Court of Final Appeal, a magistracy appeal does not require leave. In both methods of appeal, where the Judge considers appropriate, he may refer the power to hear and determine the appeal, or a point in the appeal, to the Court of Appeal.183 [1-103] In R v H...', '{"type": "case", "label": "R v Hereford Magistrates", "keywords": ["appeal", "hereford", "magistrates", "judge", "hear", "magistracy"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
