insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:zeng_liang_xin_v_hksar', 'case', 'Zeng Liang Xin v HKSAR', 'Zeng Liang Xin v HKSAR If he elects to plead guilty, the function of the court is to determine an appropriate sentence against him. Should he elect to plead not guilty, but is eventually convicted by the court, it would also be the duty of the court to sentence him appropriately. 226 Zeng Liang Xin v HKSAR (1997-98) 1 HKCFAR 12 at 22C-H. 227 Given that this a general text on substantive criminal law, the principles of sentencing will only be touched upon briefly for completen...', '{"type": "case", "label": "Zeng Liang Xin v HKSAR", "keywords": ["sentence", "text", "sentencing", "zeng", "liang", "xin"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
