insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_siu_tsz_lung', 'case', 'HKSAR v Siu Tsz-lung', 'HKSAR v Siu Tsz-lung 256 Contrary to sections 17 and 19 of the Offences against the Person Ordinance (Cap 212). 257 In HKSAR v Siu Tsz-lung (蕭子龍) (unreported, HCMA 624/2016, 13 October 2017) (Chinese Judgment), DHCJ Stanley Chan urged for a reformation of law so to allow a sentencing court to impose a suspended sentence for an offender of indecent assault. In Siu Tsz-lung, his Lordship quashed the sentence of 14 days’ imprisonment to a fine of HK$ 5,000. 258 Burglary is not...', '{"type": "case", "label": "HKSAR v Siu Tsz-lung", "keywords": ["siu", "tsz-lung", "hksar", "offences", "ordinance", "cap"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
