insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:fowler_v_padget', 'case', 'Fowler v Padget', 'Fowler v Padget [2-7] If the actus reus of the defendant is not a discrete act but a continuing one, then it will be sufficient, as a matter of law, to establish criminal liability as long as mens rea emerged at a point in time during the 1 See Chapter 4: Strict Liability and Absolute Liability Offences for further discussion. 2 Fowler v Padget (1798) 7 TR 509 at 514, 101 ER 1103 at 1106. 3 R v Wright [2011] 2 Cr App R 15. 4 ibid, at para 18. 5 ibid. 0004853935.INDD 52...', '{"type": "case", "label": "Fowler v Padget", "keywords": ["liability", "fowler", "padget", "ibid", "2-7", "actus"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
