insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_hui_yiu_fai', 'case', 'R v Hui Yiu Fai', 'R v Hui Yiu Fai Criminal Law in Hong Kong 56 [2-17] In R v Hui Yiu Fai, 28 the defendant was convicted of murder. He strangled the victim with a piece of string and subsequently threw him into the boot of a car, drove to the sea, and dumped the body into the sea with some body-building weights tied to the deceased’s body. Medical evidence revealed that the cause of death was drowning. The defendant argued that he had no intention to kill when he threw the deceased into...', '{"type": "case", "label": "R v Hui Yiu Fai", "keywords": ["he", "sea", "hui", "yiu", "fai", "defendant"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
