insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:if_further_authority_be_needed_it_comes_from_r_v_le_brun', 'case', 'If further authority be needed it comes from R v Le Brun', 'If further authority be needed it comes from R v Le Brun If further authority be needed it comes from R v Le Brun [1992] 1 QB 61 in a judgment given by Lord Lane CJ, though the facts were different, there the ‘same sequence of events’ direction was approved even though there was an appreciable time interval between the two events. [2-19] A similar situation occurred in HKSAR v Wan Kim Chung.30 The defendant strangled the deceased until she was unconscious and threw her body into the sea. Again, medical eviden...', '{"type": "case", "label": "If further authority be needed it comes from R v Le Brun", "keywords": ["was", "deceased", "further", "authority", "needed", "comes"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
