insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wan_kim_chung', 'case', 'HKSAR v Wan Kim Chung', 'HKSAR v Wan Kim Chung In the joint judgment dismissing the appeal,31 Yeung VP and McWalters J32 said the following:-33 …it is the law of Hong Kong that where a person intends to kill or inflict grievous bodily harm upon another in doing so renders that person unconscious and then, thinking that person dead, disposes of the body in a way which causes that person’s death, the person disposing of the body will be guilty of murder if, as a matter of fact, the act rendering the p...', '{"type": "case", "label": "HKSAR v Wan Kim Chung", "keywords": ["person", "hksar", "wan", "kim", "chung", "unconscious"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
