insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_instan', 'case', 'R v Instan', 'R v Instan The defendants did not, however, provide any medical assistance to the deceased and she eventually died in squalor, covered in bed sores and filth. Both defendants were convicted of manslaughter at trial and the same was affirmed by the Court of Appeal. The Court of Appeal held that as the defendants took the deceased into their home, they had voluntarily assumed a duty of care for her and had been grossly negligent in the performance of their duty. 65...', '{"type": "case", "label": "R v Instan", "keywords": ["defendants", "instan", "deceased", "was", "appeal", "had"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
