insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_jordan', 'case', 'R v Jordan', 'R v Jordan The reason for this is that it is foreseeable for a victim who was attacked to receive medical treatment and, in so doing, chances of mistreatment arise. Unless the medical treatment in question could be said to be palpably wrong, the court would be reluctant to hold that to be novus actus interveniens.96 [2-65] In R v Jordan,97 the defendant stabbed the victim, who was then admitted to hospital and eventually died. The defendant was convicted of murder...', '{"type": "case", "label": "R v Jordan", "keywords": ["was", "victim", "jordan", "who", "medical", "treatment"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
