insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:stuart_smith_lj_confirmed_that_the_correct_test_is_the_one_laid_down_in_r_v_robe', 'case', 'Stuart-Smith LJ confirmed that the correct test is the one laid down in R v Roberts', 'Stuart-Smith LJ confirmed that the correct test is the one laid down in R v Roberts Criminal Law in Hong Kong 76 [2-76] As to when the chain of causation could be broken by the victim’s own act, Stuart-Smith LJ confirmed that the correct test is the one laid down in R v Roberts, 125 where the complainant jumped out of a moving car because the defendant had assaulted and threatened her. Unless what the victim did was ‘so daft’ as to be properly classified as breaking the chain of causation, the victim’s own act would not operate as novu...', '{"type": "case", "label": "Stuart-Smith LJ confirmed that the correct test is the one laid down in R v Roberts", "keywords": ["was", "test", "victim", "what", "stuart-smith", "lj"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
