insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_hayward', 'case', 'R v Hayward', 'R v Hayward In other words, if you are sure that the defendant’s act was a cause of death, the fact that another person, or even most other people, would not have died as a result of that act is irrelevant to the issue of causation which you have to try. This is so even if the unusual or particular characteristic is one about which the defendant was unaware. [2-81] In R v Hayward,131 the victim, who was suffering from persistent illness, collapsed and died after th...', '{"type": "case", "label": "R v Hayward", "keywords": ["defendant", "was", "died", "woman", "hayward", "other"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
