insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_defendant_was_convicted_of_manslaughter_and_his_appeal_was_dismissed_in_r_v_', 'case', 'The defendant was convicted of manslaughter and his appeal was dismissed. In R v Dear', 'The defendant was convicted of manslaughter and his appeal was dismissed. In R v Dear Criminal Law in Hong Kong 78 [2-83] Similar to Blaue, 133 a victim who neglects his injury or, worse, aggravates the seriousness of his own injury, is unlikely to affect the chain of causation. In R v Wall,134 the deceased was subject to an illegal flogging, then voluntarily consumed spirits to ease the pain, which eventually led to his death. The defendant was convicted of manslaughter and his appeal was dismissed. In R v Dear, 135 the defendant’s conv...', '{"type": "case", "label": "The defendant was convicted of manslaughter and his appeal was dismissed. In R v Dear", "keywords": ["was", "his", "defendant", "dear", "deceased", "convicted"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
