insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_lee_kwan_kong', 'case', 'HKSAR v Lee Kwan Kong', 'HKSAR v Lee Kwan Kong 2.1 Direct intent [3-8] In essence, direct intent means ‘aim and purpose’. Professor RA Duff provides a helpful conceptualisation in the form of a ‘success and failure’ test. The question is this: would I regard my directly intended project or plan as having failed, if the thing I foresaw as certain did not occur? 3 In most cases, the word ‘intention’ does not require further explanation to the jury.4 The Specimen Directions suggest that the following p...', '{"type": "case", "label": "HKSAR v Lee Kwan Kong", "keywords": ["hksar", "lee", "kwan", "kong", "direct", "intent"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
