insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:as_observed_by_lord_griffith_in_r_v_court', 'case', 'As observed by Lord Griffith in R v Court', 'As observed by Lord Griffith in R v Court 81 Mens Rea You must be sure that, when the defendant did the act, he intended [e.g. to kill the victim]. You decide intent by considering what the defendant did or did not do [and the effect of his actions or inaction] and by what he said or did not say. You should look at his actions before, at the time of and after (the alleged offence). All these things may shed light on his intention at the critical time. [3-9] ‘Intent’ is nonetheless not ‘motive’....', '{"type": "case", "label": "As observed by Lord Griffith in R v Court", "keywords": ["did", "you", "intent", "do", "his", "motive"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
