insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:more_recently_in_r_v_hales', 'case', 'More recently in R v Hales', 'More recently in R v Hales The Court of Appeal held that if a person’s direct purpose in approaching a ‘prohibited place’ was to cause obstruction or interference that is prejudicial to the defence dispositions of the State, an offence would have been committed, and the indirect purposes or motives of the accused did not alter the nature or content of his offence. [3-11] More recently in R v Hales,9 which involved a charge of attempted murder, the defendant escaped arrest, got in...', '{"type": "case", "label": "More recently in R v Hales", "keywords": ["was", "police", "more", "recently", "hales", "offence"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
