insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:chandler_v_dpp', 'case', 'Chandler v DPP', 'Chandler v DPP [3-15] The principle of ‘oblique intent’ was created to remedy the above situations, where a person possesses oblique intent, in which the ensuing event is a natural consequence of the voluntary act and it is reasonably foresee as such. 2.2.1 R v Moloney [3-16] In R v Moloney,15 the defendant, who had been drinking heavily alongside his stepfather, fired a shotgun, the pellets from which hit his stepfather. His stepfather was killed instantly. At trial,...', '{"type": "case", "label": "Chandler v DPP", "keywords": ["was", "defendant", "his", "stepfather", "chandler", "dpp"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
