insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:caldwell_test_was_treated_as_authoritative_in_r_v_chau_ming_cheong', 'case', 'Caldwell test was treated as authoritative in R v Chau Ming Cheong', 'Caldwell test was treated as authoritative in R v Chau Ming Cheong 92 Criminal Law in Hong Kong destroyed or damaged. This case epitomises the harshness of the Caldwell test on minors and those with reduced intellectual capacities - as they are judged against the ‘reasonably prudent’ hypothetical construct.64 3.2.3 Application of Caldwell in Hong Kong [3-41] In Hong Kong, the Caldwell test was treated as authoritative in R v Chau Ming Cheong, 65 a manslaughter case. The Court of Appeal considered a father who, over a l...', '{"type": "case", "label": "Caldwell test was treated as authoritative in R v Chau Ming Cheong", "keywords": ["caldwell", "test", "hong", "kong", "was", "treated"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
