insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:sin_kam_wah_v_hksar', 'case', 'Sin Kam Wah v HKSAR', 'Sin Kam Wah v HKSAR In short, the highest court in Hong Kong decided to follow in the footsteps of R v G88 in response to the vehement criticism of the old law. [3-48] In Sin Kam Wah,89 Sin (D1) was a senior superintendent and was charged with offences of misconduct in public office. D1 accepted from D2, who beneficially owned four nightclubs, free sexual services from women over whom he knew D2 exercised control. D1 argued, on appeal, that the trial judge misdirected hims...', '{"type": "case", "label": "Sin Kam Wah v HKSAR", "keywords": ["sin", "kam", "wah", "was", "d1", "d2"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
