insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chan_tak_ming_paddy_100_for_now', 'case', 'HKSAR v Chan Tak Ming Paddy.100 For now', 'HKSAR v Chan Tak Ming Paddy.100 For now [3-52] As a result, applying this new understanding of recklessness to the offence of misconduct in public office, it is clear that the misconduct must be deliberate rather than accidental in the sense that the official must either knows that his or her conduct is unlawful or wilfully disregard the risk that their conduct is unlawful. Wilful misconduct that is without reasonable excuse or justification is culpable. [3-53] Since then, the conception of s...', '{"type": "case", "label": "HKSAR v Chan Tak Ming Paddy.100 For now", "keywords": ["hksar", "recklessness", "misconduct", "chan", "tak", "ming"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
