insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hin_lin_yee_v_hksar', 'case', 'Hin Lin Yee v HKSAR', 'Hin Lin Yee v HKSAR Applying such reasoning, Lord Sumption considered that strict liability was inappropriate for the offence of aggravated vehicle taking causing injury to another person.9 Instead, there must at least some act or omission in relation to the defendant’s control of the vehicle which allows an element of fault to be inferred and that this act or omission had contributed in a more than minimal way to the accident. 3 Hin Lin Yee v HKSAR [2010] 3 HKC 403, (2010...', '{"type": "case", "label": "Hin Lin Yee v HKSAR", "keywords": ["er", "hksar", "act", "ac", "hin", "lin"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
