insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:strict_liability_and_absolute_liability_offences_of_displacing_the_presumption_i', 'case', 'Strict Liability and Absolute Liability Offences of displacing the presumption. In Kwong Hung-Fai v The Queen', 'Strict Liability and Absolute Liability Offences of displacing the presumption. In Kwong Hung-Fai v The Queen 123 Strict Liability and Absolute Liability Offences of displacing the presumption. In Kwong Hung-Fai v The Queen, 92 the Hong Kong court went even further to expressly state that the nature of the penalty is a weighty consideration. This does not, however, mean that the converse is true, viz, the mere fact that an offence has a ‘comparatively slight’ impact upon conviction is not in itself a sufficient basis for imposing absolute liability. 4.3 Statuto...', '{"type": "case", "label": "Strict Liability and Absolute Liability Offences of displacing the presumption. In Kwong Hung-Fai v The Queen", "keywords": ["liability", "offence", "absolute", "strict", "offences", "displacing"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
