insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:although_ab_v_hm_advocate_was_decided_in_the_context_of_compliance_with_the_echr', 'case', 'Although AB v HM Advocate was decided in the context of compliance with the ECHR', 'Although AB v HM Advocate was decided in the context of compliance with the ECHR Although AB v HM Advocate was decided in the context of compliance with the ECHR,120 in Hong Kong, Lam Kwong Wai121 seems to suggest that the margin would be even more relevant to serious offences. As noted by the Court of Final Appeal:-122 The weight to be accorded to the legislative judgment by the Court will vary from case to case depending upon the nature of the problem, whether the executive and the legislature are better equipped than the courts t...', '{"type": "case", "label": "Although AB v HM Advocate was decided in the context of compliance with the ECHR", "keywords": ["although", "ab", "hm", "advocate", "was", "decided"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
