insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_lam_kwong_wai', 'case', 'HKSAR v Lam Kwong Wai', 'HKSAR v Lam Kwong Wai [4-66] To conclude, the main takeaway is that although the courts are increasingly aware of the potential ramifications of strict/absolute liability offences on the presumption of innocence, deference to the legislature remains the norm. 120 ibid. 121 HKSAR v Lam Kwong Wai (2006) 9 HKCFAR 574, [2006] HKCU 1465. 122 ibid, at para 45. 0004853937.INDD 129 10-06-2020 14:16:00', '{"type": "case", "label": "HKSAR v Lam Kwong Wai", "keywords": ["hksar", "lam", "kwong", "wai", "ibid", "4-66"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
