insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chan_man_lok', 'case', 'HKSAR v Chan Man Lok', 'HKSAR v Chan Man Lok That said, the court has held that this is not an ‘insurmountable obstacle’ to a conviction of murder.12 Killing can still be proven if the defendant himself confesses that the deceased is dead, 13 or through circumstantial evidence.14 [5-13] In HKSAR v Chan Man Lok,15 the infamous ‘Hello Kitty’ killing case in which the body of the deceased was dismembered, the defendants were acquitted of murder but convicted of manslaughter at trial. There was no dir...', '{"type": "case", "label": "HKSAR v Chan Man Lok", "keywords": ["deceased", "evidence", "was", "hksar", "chan", "man"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
