insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_rule_operates_as_described_by_lord_alverstone_in_r_v_dyson', 'case', 'The rule operates as described by Lord Alverstone in R v Dyson', 'The rule operates as described by Lord Alverstone in R v Dyson Homicide 135 [5-15] Before 1 June 2000the rule of a year and a day, a legal fiction, still prevailed in the law of homicide. The rule operates as described by Lord Alverstone in R v Dyson: ‘where the death does not occur within a year and a day after the injury was inflicted, for in that event it must be attributed to some other cause’.18 This rule has been criticised as being incongruent with the general rules of causation, and as a prototype of obsole...', '{"type": "case", "label": "The rule operates as described by Lord Alverstone in R v Dyson", "keywords": ["year", "day", "operates", "described", "lord", "alverstone"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
