insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_ma_kwok_fai', 'case', 'HKSAR v Ma Kwok Fai', 'HKSAR v Ma Kwok Fai Criminal Law in Hong Kong 138 Thus, the requisite mens rea in a case concerning murder remains that a defendant must have the intent to cause ‘death’ or ‘grievous bodily harm’. [5-25] The courts have also commented on the many attempts judges have made to explain ‘grevious bodily harm’ to juries. In HKSAR v Ma Kwok Fai,36 the Court of Appeal held that it is preferable for judges to explain to the jury that ‘grievous bodily harm’ simply means ‘really ser...', '{"type": "case", "label": "HKSAR v Ma Kwok Fai", "keywords": ["bodily", "harm", "defendant", "hksar", "ma", "kwok"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
