insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:dpp_v_smith', 'case', 'DPP v Smith', 'DPP v Smith [5-27] Under the current legal framework, a defendant convicted of murder is subject to a mandatory life sentence, leaving the judge with no residual discretion to impose alternative sentences. This also means that the judge is not entitled to take into account any mitigating factors when sentencing the defendant. On the other hand, a conviction of manslaughter allows the judge an immensely wide discretion to impose any sentence he deems fit, bearing in...', '{"type": "case", "label": "DPP v Smith", "keywords": ["sentence", "judge", "ac", "er", "dpp", "smith"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
