insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:tindal_cj_said_in_rex_v_hayward_74', 'case', 'Tindal CJ said in Rex v Hayward 74', 'Tindal CJ said in Rex v Hayward 74 Criminal Law in Hong Kong 148 The original reasons in this branch of the law were largely reasons of the heart and of common sense, not the reasons of pure juristic logic. The potentiality of provocation to reduce murder to manslaughter was, as Tindal CJ said in Rex v Hayward 74, ‘in compassion of human infirmity.’ But justice and common sense then demanded some limitation: it would be unjust that the drunk man or one exceptionally pugnacious or bad tem...', '{"type": "case", "label": "Tindal CJ said in Rex v Hayward 74", "keywords": ["reasons", "tindal", "cj", "said", "rex", "hayward"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
