insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_jutting', 'case', 'HKSAR v Jutting', 'HKSAR v Jutting The Court of Appeal held that the trial judge ought to have directed the jury to decide: (1) Whether the defendant suffered from a dependency of such a nature and extent as to constitute an abnormality of mind; (2) If so, whether it was caused by disease or illness; and (3) If so, whether the impact of that abnormality of mind was present at the time of the killing. If the jury is satisfied with findings of the above, it shall finally consider the issue...', '{"type": "case", "label": "HKSAR v Jutting", "keywords": ["whether", "jury", "abnormality", "mind", "was", "hksar"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
