insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:similar_sentiments_were_expressed_by_lord_parker_cj_in_r_v_byrne', 'case', 'Similar sentiments were expressed by Lord Parker CJ in R v Byrne', 'Similar sentiments were expressed by Lord Parker CJ in R v Byrne … Substantial does not mean total, that is to say the mental responsibility need not be totally impaired, so to speak, destroyed altogether. At the end of the scale substantial does not mean trivial or minimal. It is something in between and [the legislature] has left it to [the jury]. Similar sentiments were expressed by Lord Parker CJ in R v Byrne, 134 in which his Lordship held that whether the impairment could be properly considered as substantial i...', '{"type": "case", "label": "Similar sentiments were expressed by Lord Parker CJ in R v Byrne", "keywords": ["substantial", "responsibility", "jury", "similar", "sentiments", "were"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
