insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:this_was_exemplified_in_r_v_watson', 'case', 'This was exemplified in R v Watson', 'This was exemplified in R v Watson [5-105] This was exemplified in R v Watson, 158 in which the criminal act, burglary, was found to be unlawful and dangerous because the jury was entitled to take into account that during the course of the unlawful act (ie during his entire intrusion), the defendant must have become aware of the victim’s approximate age and frailty. By contrast, the court in R v Bristow held that while burglary per se was not a dangerous crime, a particular burglary migh...', '{"type": "case", "label": "This was exemplified in R v Watson", "keywords": ["was", "burglary", "act", "dangerous", "exemplified", "watson"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
