insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:mental_or_emotional_harm_is_insufficient_in_r_v_dawson', 'case', 'Mental or emotional harm is insufficient. In R v Dawson', 'Mental or emotional harm is insufficient. In R v Dawson Mental or emotional harm is insufficient. In R v Dawson,160 the victim died from a heart attack following an attempted robbery in their home. It was held that an emotional disturbance, such as shock produced by fright in that case, was not sufficient to constitute harm. The Court of Appeal held that the jury was therefore given a misdirection and the conviction was quashed. 156 As McMullin NPJ then was. 157 R v Chau Ming Cheong [1983] 1 HKC 68, [1983] H...', '{"type": "case", "label": "Mental or emotional harm is insufficient. In R v Dawson", "keywords": ["was", "emotional", "harm", "dawson", "mental", "insufficient"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
