insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_wacker', 'case', 'R v Wacker', 'R v Wacker 6.1 Actus reus of gross negligence manslaughter [5-112] One must differentiate between the duty of care in the civil sense (under the law of negligence) and in the criminal sense. Although there have been judicial statements suggesting that the ordinary principles of the law of negligence are generally applicable to cases of gross negligence manslaughter,168 in practice there seems to be no consistent consensus as 166 R v Adomako [1995] 1 AC 171, [1994]...', '{"type": "case", "label": "R v Wacker", "keywords": ["negligence", "duty", "care", "was", "wacker", "gross"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
