insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_kong_cheuk_kwan', 'case', 'R v Kong Cheuk-kwan', 'R v Kong Cheuk-kwan In the context of gross negligence manslaughter, it is for the jury to decide whether a duty of care existed and whether it was owed to the deceased. A failure to perform a statutory duty,173 or failing to observe signals on the road, 174 are some examples of situations in which an omission could satisfy the actus reus of gross negligence manslaughter. 6.2 Mens rea of gross negligence manslaughter [5-115] The orthodox position is that the mens rea of gr...', '{"type": "case", "label": "R v Kong Cheuk-kwan", "keywords": ["gross", "negligence", "manslaughter", "kong", "cheuk-kwan", "jury"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
