insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:a_similar_decision_was_made_in_r_v_ireland', 'case', 'A similar decision was made in R v Ireland', 'A similar decision was made in R v Ireland We reject the submission of Mr Hurst that a person cannot have a fear of immediate violence unless that person can see the potential perpetrator of that violence. [6-7] A similar decision was made in R v Ireland,11 in which the defendant made numerous ‘silent’ telephone calls to three different women. The House of Lords in that case held that although the defendant did not say anything, those silent telephone calls fulfilled the necessary actus reus of...', '{"type": "case", "label": "A similar decision was made in R v Ireland", "keywords": ["was", "person", "violence", "defendant", "similar", "decision"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
