insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_shek_kwok_ngai', 'case', 'HKSAR v Shek Kwok Ngai', 'HKSAR v Shek Kwok Ngai That still leaves unanswered the question ‘when is a touching to be called hostile?’ Hostility cannot be equated with ill-will or malevolence. It cannot be governed by the obvious intention shown in acts like punching, stabbing or shooting. It cannot be solely governed by an expressed intention, although that may be strong evidence. But the element of hostility, in the sense in which it is now to be considered, must be a question of fact for the tribuna...', '{"type": "case", "label": "HKSAR v Shek Kwok Ngai", "keywords": ["hostility", "cannot", "hksar", "shek", "kwok", "ngai"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
