insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:oapo_was_considered_in_hksar_v_estrella', 'case', 'OAPO was considered in HKSAR v Estrella', 'OAPO was considered in HKSAR v Estrella It subsequently follows that it is unnecessary for the prosecution to show that the accused intended or foresaw that the unlawful act might cause physical harm of the gravity described in the section, that is, either actual or grievous bodily harm. The underlying rationale is that the scope of the section would otherwise be too limited. [6-36] In Hong Kong, recklessness as the mens rea for section 19 of the OAPO was considered in HKSAR v Estrella, Hazim...', '{"type": "case", "label": "OAPO was considered in HKSAR v Estrella", "keywords": ["oapo", "was", "considered", "hksar", "estrella", "harm"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
