insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_estrella', 'case', 'HKSAR v Estrella', 'HKSAR v Estrella (supra), there is no doubt that Caldwell recklessness has for all intents and purposes left the criminal law. It has certainly left section 19 of the Ordinance. For a defendant to be convicted of a criminal offence on the basis of recklessness, it has to be proven that the defendant consciously saw the risk of injury to the victim and went ahead with his or her actions in any event. 67 R v Savage (Susan) [1992] 1 AC 699, [1991] 4 All ER 698. The Court w...', '{"type": "case", "label": "HKSAR v Estrella", "keywords": ["hksar", "estrella", "recklessness", "left", "criminal", "defendant"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
