insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_mowatt', 'case', 'R v Mowatt', 'R v Mowatt Non-fatal Offences Against Persons 191 [6-37] Since there was a real possibility that the defendant did not realise that the victim’s finger had intruded into the door recess, she therefore did not intend the specific injury and also did not foresee the risk of injury to the victim as a result of her slamming the door. Hence, the defendant’s conviction was quashed. 3.2.2 The ulterior intent under section 17 of the OAPO [6-38] In R v Mowatt, 71 the appel...', '{"type": "case", "label": "R v Mowatt", "keywords": ["did", "mowatt", "against", "was", "defendant", "victim"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
