insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_kwan_kin_sum', 'case', 'HKSAR v Kwan Kin Sum', 'HKSAR v Kwan Kin Sum If, for some reason, the police officer was acting ultra vires and, therefore, not in the due course of execution of duty, a defendant will not be found guilty of the offence. [6-44] In HKSAR v Kwan Kin-sum, 76 the defendant was stopped by a police constable because he was suspected of possessing dangerous drugs. Another police sergeant (who was in plain clothes) arrived and the defendant walked away briskly. When the sergeant tried to stop the 75 Polic...', '{"type": "case", "label": "HKSAR v Kwan Kin Sum", "keywords": ["police", "was", "hksar", "kwan", "defendant", "kin"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
