insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:commissioner_per_hksar_v_yeung_ka_yee', 'case', 'Commissioner. Per HKSAR v Yeung Ka-yee', 'Commissioner. Per HKSAR v Yeung Ka-yee Non-fatal Offences Against Persons 197 and residence or detained under section 54, shall be forthwith delivered into the custody of the officer in charge of a police station or a police officer authorized in that behalf by the Commissioner. Per HKSAR v Yeung Ka-yee, 87 ‘forthwith’ does not necessarily mean ‘immediately’ if there are very good reasons for a delay. 4.1.2 Power of stop, detain and search [6-53] The main provision providing for the power of...', '{"type": "case", "label": "Commissioner. Per HKSAR v Yeung Ka-yee", "keywords": ["police", "commissioner", "per", "hksar", "yeung", "ka-yee"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
