insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_yeung_ka_yee', 'case', 'HKSAR v Yeung Ka-yee', 'HKSAR v Yeung Ka-yee (3) In this section, proof of identity (身分證明文件) has the same meaning as in section 17B of the Immigration Ordinance (Cap. 115). 87 HKSAR v Yeung Ka-yee [2003] 2 HKC 540, per Stuart-Moore VP, Stock and Yeung JJA (as Stock NPJ and Yeung VP then were). 0004853939.INDD 197 6/10/2020 6:33:19 PM', '{"type": "case", "label": "HKSAR v Yeung Ka-yee", "keywords": ["yeung", "hksar", "ka-yee", "vp", "stock", "3)"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
