insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_b', 'case', 'R v B', 'R v B Accordingly, it was possible that the defendant mistakenly believed that the complainant had consented to buggery. The mere fact the defendant and the complainant gave different 36 This was de facto overturned by the Sexual Offences Act 2003. In R v B (2013) 1 Cr App R 36 at para 36, the English Court of Appeal described this as a ‘conscious departure’ from the previous position. The court further clarified that delusional beliefs, namely those arising...', '{"type": "case", "label": "R v B", "keywords": ["was", "defendant", "complainant", "accordingly", "possible", "mistakenly"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
