insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_cheung_hok_man', 'case', 'HKSAR v Cheung Hok Man', 'HKSAR v Cheung Hok Man Sexual Offences 223 accounts as to what happened could not lead the trial judge to decline to direct on genuine belief. [7-25] In HKSAR v Cheung Hok Man,39 the defendant and the complainant had previously engaged in intimate internet communications and intimate acts. As a result, the defendant might have mistakenly believed that the complainant had consented to sexual acts. In addition, the defendant also denied having sexual intercourse with the compla...', '{"type": "case", "label": "HKSAR v Cheung Hok Man", "keywords": ["sexual", "complainant", "acts", "defendant", "had", "intimate"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
