insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_shing_chung', 'case', 'HKSAR v Wong Shing-chung', 'HKSAR v Wong Shing-chung [7-26] In HKSAR v Wong Shing-chung,40 the Court of Appeal held that the relevant element was whether the defendant ‘genuinely believed’ rather than ‘honestly believed’ that the complainant consented to sexual intercourse with him. Hence, even if the belief of the defendant was based upon wrong or unreasonable grounds, that would be of no relevance. (c) Recklessness [7-27] In section 118(3)(a) of the CO, ‘recklessness’ bears its general meaning in crimin...', '{"type": "case", "label": "HKSAR v Wong Shing-chung", "keywords": ["hksar", "wong", "shing-chung", "was", "defendant", "believed"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
