insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:secretary_for_justice_v_chung_yui_hung', 'case', 'Secretary for Justice v Chung Yui Hung', 'Secretary for Justice v Chung Yui Hung Criminal Law in Hong Kong 228 123. Intercourse with girl under 13 A man who has unlawful sexual intercourse with a girl under the age of 13 shall be guilty of an offence and shall be liable on conviction on indictment to imprisonment for life. [7-41] Courts have noted that it is a ‘particularly grave offence’ to engage in sexual intercourse with a girl under the age of 13. In Secretary for Justice v Chung Yui Hung, 54 despite the defendant’s previously...', '{"type": "case", "label": "Secretary for Justice v Chung Yui Hung", "keywords": ["age", "defendant", "intercourse", "girl", "secretary", "justice"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
