insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_leading_authority_in_this_area_is_r_v_court', 'case', 'The leading authority in this area is R v Court', 'The leading authority in this area is R v Court (4) A woman who is mentally incapacitated person cannot in law give any consent which would prevent an act being an assault for the purposes of this section, but a person is only to be treated as guilty of indecently assaulting a mentally incapacitated person by reason of that incapacity to consent, if that person knew or had reason to suspect her to be a mentally incapacitated person. [7-50] The leading authority in this area is R v Court, in which the...', '{"type": "case", "label": "The leading authority in this area is R v Court", "keywords": ["person", "assault", "mentally", "incapacitated", "leading", "authority"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
