insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:this_is_illustrated_by_r_v_george', 'case', 'This is illustrated by R v George', 'This is illustrated by R v George A simpler way of putting it for the jury is whether ‘right-minded persons would consider the conduct indecent or not’ - in other words, whether what occurred was so offensive by contemporary standards of modesty and privacy as to be considered indecent.75 [7-58] Furthermore, if the circumstances of the assault are incapable of being regarded as indecent, the undisclosed intention of the accused could not make the assault an indecent one.76 This is illus...', '{"type": "case", "label": "This is illustrated by R v George", "keywords": ["indecent", "circumstances", "assault", "illustrated", "george", "whether"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
