insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wan_ho_yeung', 'case', 'HKSAR v Wan Ho Yeung', 'HKSAR v Wan Ho Yeung [7-59] Nor is it necessary to prove that the complainant was aware of the circumstances of indecency or apprehended indecency. An indecent assault can be committed by the touching of someone who is asleep or unconscious.78 [7-60] In HKSAR v Wan Ho Yeung,79 the defendant put the complainant’s feet on his mouth for two to three minutes, so that he could sniff her feet while breathing. As feet were body parts that other people did not readily have contact...', '{"type": "case", "label": "HKSAR v Wan Ho Yeung", "keywords": ["was", "feet", "indecent", "defendant", "hksar", "wan"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
