insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_ng_wah_choy', 'case', 'HKSAR v Ng Wah Choy', 'HKSAR v Ng Wah Choy Criminal Law in Hong Kong 234 Similarly, in HKSAR v Ng Wah Choy,80 the defendant, a teacher, kissed the complainant’s hands and face multiple times and inserted his right hand into her sleeve touching her right arm during class. It was held that such acts had gone far beyond what a teacher should have done when teaching a student and that a reasonable man would have considered the appellant’s acts indecent.81 [7-61] The Law Reform Commission has propose...', '{"type": "case", "label": "HKSAR v Ng Wah Choy", "keywords": ["hksar", "ng", "wah", "choy", "teacher", "right"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
