insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wan_yat_man', 'case', 'HKSAR v Wan Yat Man', 'HKSAR v Wan Yat Man The appellant’s admission of ‘buttock fetish’ was clearly such material. It tended to confirm, as indeed did the events leading up to the assault and the appellant’s conduct immediately thereafter, that what he did was to satisfy his peculiar sexual appetite. It was additional relevant evidence. It tended to establish the sexual undertones which gave the assault its true cachet. [7-63] In HKSAR v Wan Yat Man, 84 the defendant was the immediate superior...', '{"type": "case", "label": "HKSAR v Wan Yat Man", "keywords": ["was", "hksar", "wan", "yat", "man", "appellant"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
