insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:chan_wai_hung_v_hksar', 'case', 'Chan Wai Hung v HKSAR', 'Chan Wai Hung v HKSAR 5.2 Indecent conduct towards a child under 16 years of age: section 146 of the CO [7-67] Section 146 of the CO stipulates that:- 146. Indecent conduct towards child under 16 (1) Subject to subsection (3), a person who commits an act of gross indecency with or towards a child under the age of 16, or who incites a child under the age of 16 to commit such an act with or towards him or her or another, shall be guilty of an offence and shall be liable on con...', '{"type": "case", "label": "Chan Wai Hung v HKSAR", "keywords": ["towards", "child", "age", "ibid", "chan", "wai"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
