insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_tang_siu_fung', 'case', 'HKSAR v Tang Siu Fung', 'HKSAR v Tang Siu Fung The Court of Appeal allowed the appeal on the basis that the prosecution’s reliance on the section 76 presumptions was misplaced. The complainant knew full well what she was being asked to do and what she did in fact do, namely perform a sexual act. She could have been in no doubt that the motive was at least in part sexual gratification. Therefore, on the subject of deceit, there was no evidence as to purpose. 109 Consultation Paper, Rape and Other Non...', '{"type": "case", "label": "HKSAR v Tang Siu Fung", "keywords": ["was", "she", "sexual", "no", "hksar", "tang"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
