insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:lawrence_v_commissioner_of_police_for_the_metropolis', 'case', 'Lawrence v Commissioner of Police for the Metropolis', 'Lawrence v Commissioner of Police for the Metropolis In fact, it has been broadened to an extent that it has been criticised for being reduced to near nothingness. As a ‘health warning’, ‘appropriation’ has now developed to become a concept that could not be neatly classified as an actus reus - rather it has overlapped to some extent with the concept of dishonesty. 2.1.1 Lawrence v Commissioner of Police for the Metropolis [8-8] In Lawrence v Commissioner of Police for the Metropolis, 3 the defendant, who...', '{"type": "case", "label": "Lawrence v Commissioner of Police for the Metropolis", "keywords": ["lawrence", "commissioner", "police", "metropolis", "extent", "concept"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
