insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_cho_sum_put_these_principles_in_the_context_of_appropriation_of_cho', 'case', 'HKSAR v Wong Cho Sum put these principles in the context of appropriation of chose in action', 'HKSAR v Wong Cho Sum put these principles in the context of appropriation of chose in action Both are the subject of the disapprobation of ordinary right-thinking citizens and the distinction is liable to be arbitrary or at least strongly influenced by considerations subjective to the individual members of the tribunal. To treat otherwise lawful conduct as criminal merely because it is open to such disapprobation would be contrary to principle and open to the objection that it fails to achieve the objective and transparent certainty required of...', '{"type": "case", "label": "HKSAR v Wong Cho Sum put these principles in the context of appropriation of chose in action", "keywords": ["principles", "hksar", "wong", "cho", "sum", "put"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
