insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_wong_cho_sum', 'case', 'HKSAR v Wong Cho Sum', 'HKSAR v Wong Cho Sum And where there is an act of appropriation, in other words an act by which the fraudster assumes the rights of the owner of the chose in action, and the thing recoverable by action is diminished or extinguished by the act of appropriation, then the fraudster is guilty of theft… Thus far, applying the principles to the present case, it seems beyond argument that the defendant who himself operates an ATM to effect a withdrawal from another’s account… and...', '{"type": "case", "label": "HKSAR v Wong Cho Sum", "keywords": ["hksar", "wong", "cho", "sum", "act", "appropriation"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
