insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:anderton_v_burnside', 'case', 'Anderton v Burnside', 'Anderton v Burnside [8-19] The ever-widening notion of appropriation, coupled with it being elided with ‘dishonesty’, has led to the disconcerting conclusion that it is venturing into the territory of fraud. This worrying prospect materialised in the following two cases. 30 R v Morris; Anderton v Burnside [1984] AC 320 at 334G-335C, [1983] 3 All ER 288 at 295C-E. 31 Section 1(1) of the Theft Act 1968, which provides that ‘a person is guilty of theft if he dishonestly appro...', '{"type": "case", "label": "Anderton v Burnside", "keywords": ["theft", "anderton", "burnside", "act", "provides", "person"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
