insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:an_interesting_authority_is_r_v_forrester', 'case', 'An interesting authority is R v Forrester', 'An interesting authority is R v Forrester Aside from laying down the definition of ‘theft’, section 2(1) of the TO also stipulates, inter alia, that stealing shall be construed as a synonym of theft.90 87 R v Cockburn (John James) [1968] 1 All ER 466 at 468I-469B. 88 R v Velumyl [1989] Crim LR 299. 89 ibid. 90 An interesting authority is R v Forrester [1992] Crim LR 792 where the English court doubted whether the word ‘steal’ bore the same statutory definition of theft. It is submitted that thi...', '{"type": "case", "label": "An interesting authority is R v Forrester", "keywords": ["theft", "definition", "interesting", "authority", "forrester", "down"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
