insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_ancient_case_of_r_v_harman', 'case', 'the ancient case of R v Harman', 'the ancient case of R v Harman Criminal Law in Hong Kong 266 3.2 Immediately before or at the time of doing so and in order to steal [8-69] The timing of the use of force is crucial. One should not lose sight of the fact that ‘robbery’ is not an offence of violence per se.97 If force is used after a theft has been completed, this is not considered robbery. 98 In the ancient case of R v Harman, 99 the defendant picked the victim’s pocket without the victim notiving. Yet, when the vict...', '{"type": "case", "label": "the ancient case of R v Harman", "keywords": ["victim", "defendant", "robbery", "ancient", "case", "harman"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
