insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_james', 'case', 'R v James', 'R v James The Court of Appeal quashed the defendant’s conviction of robbery, holding that the force subjected by the victim must be then and there. 4. Burglary and Aggra v ated Burglary [8-72] The TO created two offences of burglary. For easy discussion, these will be referred to as the offence of burglary simpliciter and aggravated burglary. 97 R v Baker (Wendy Ann) [2001] Crim App R (S) 55. 98 It is important to note that the defendant may have committed a sepa...', '{"type": "case", "label": "R v James", "keywords": ["burglary", "crim", "james", "defendant", "app", "separate"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
