insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:robson_v_hallett', 'case', 'Robson v Hallett', 'Robson v Hallett The Court of Appeal upheld his conviction of aggravated burglary. [8-96] Since the defendant was charged under the English equivalent of section 11(1)(b) of the TO, the burglary as charged was not complete until he committed the theft, at which time he had the kitchen knife in his hand. The offence of burglary is complete at the time when a defendant is proven to have with him a weapon of offence. It would have been different if the charge was based on...', '{"type": "case", "label": "Robson v Hallett", "keywords": ["burglary", "was", "complete", "he", "robson", "hallett"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
