insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_brooks_and_brooks', 'case', 'R v Brooks and Brooks', 'R v Brooks and Brooks (3) Subsection (1) shall not apply where the supply of the goods or the doing of the service is contrary to law, or where the service done is such that payment is not legally enforceable. [8-98] In Pill LJ’s words, it is ‘intended to create a simple and straightforward offence’. 130 The elements of the offence, as plainly stipulated in the provision, are as follows: (1) Insofar as the actus reus is concerned: (a) The defendant made off; and (b) He did s...', '{"type": "case", "label": "R v Brooks and Brooks", "keywords": ["brooks", "off", "he", "so", "1)", "doing"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
