insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:a_mere_intention_to_delay_or_defer_payment_is_not_enough_in_r_v_allen', 'case', 'A mere intention to delay or defer payment is not enough. In R v Allen', 'A mere intention to delay or defer payment is not enough. In R v Allen As a result, the driver could not lawfully demand fare, and the defendant was never in a situation in which he was bound to pay or even tender the money for the journey. 5.2 Mens rea 5.2.1 Dishonesty [8-104] The principles on dishonesty are the same as those discussed above for theft.138 5.2.2 Intent to avoid payment [8-105] The prosecution must show that the defendant intended to permanently avoid payment. A mere intention to delay or defer payment is...', '{"type": "case", "label": "A mere intention to delay or defer payment is not enough. In R v Allen", "keywords": ["payment", "intention", "defendant", "avoid", "mere", "delay"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
