insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_au_ngan_yi', 'case', 'HKSAR v Au Ngan-yi', 'HKSAR v Au Ngan-yi [8-106] In HKSAR v Au Ngan-yi,141 there were heated arguments between a taxi driver and the defendant (a passenger) regarding the amount of taxi fare payable. DHCJ Pang142 held that there was no intent to avoid payment judging from the fact that the defendant had argued with the driver for over 10 minutes and had even requested a passer-by to report the matter to the police. The defendant had also voluntarily boarded the police car. All these indicated...', '{"type": "case", "label": "HKSAR v Au Ngan-yi", "keywords": ["defendant", "had", "police", "hksar", "au", "ngan-yi"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
