insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_tokeley_parry', 'case', 'R v Tokeley-Parry', 'R v Tokeley-Parry If there is any uncertainty about which form of handling, two counts will generally cover every form: one count for the first limb, dishonestly receiving, and a second for the second limb, dishonestly undertaking or assisting in the retention, removal, disposal or realisation, with arrangement to do those things if need be. The second count, covering all those alternatives, would not be bad for duplicity and might be advisable. [8-111] In R v Tokeley-Pa...', '{"type": "case", "label": "R v Tokeley-Parry", "keywords": ["second", "tokeley-parry", "form", "count", "limb", "dishonestly"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
