insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_zheng_wan_tai', 'case', 'HKSAR v Zheng Wan Tai', 'HKSAR v Zheng Wan Tai Dishonesty Offences 279 it more difficult and less profitable to dispose of stolen property. Thus, the definition of handling stolen goods has been extended by that section to include not only the buying of property, but also other ways such as facilitating its disposal. [8-112] In HKSAR v Zheng Wan Tai,149 Stuart-Moore VP discussed the doctrine of ‘recent possession’, holding that it could be applied to all forms of handling. His Lordship further expla...', '{"type": "case", "label": "HKSAR v Zheng Wan Tai", "keywords": ["stolen", "goods", "doctrine", "possession", "hksar", "zheng"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
