insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:roe_v_kingerlee', 'case', 'Roe v Kingerlee', 'Roe v Kingerlee 1.1 Destroys or damages [9-3] Section 60 2 of the CO is silent as to what amounts to ‘destroy’ or ‘damage’. Whether an act constitutes ‘destroying’ or ‘damaging’ is a matter of fact and degree, the assessment of which requires everyday common sense.3 1 Crimes Ordinance (Cap 200). 2 Including both section 60(1) of the CO for criminal damage simpliciter and section 60(2) of the CO for aggravated criminal damage. 3 Roe v Kingerlee [1986] Crim LR 735. 00048...', '{"type": "case", "label": "Roe v Kingerlee", "keywords": ["co", "damage", "roe", "kingerlee", "criminal", "destroys"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
