insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_luk_kai_sing', 'case', 'HKSAR v Luk Kai Sing', 'HKSAR v Luk Kai Sing [9-20] Should one compare the offence of criminal damage simpliciter with the offence of ‘aggravated’ criminal damage, one would notice that they differ in three main respects: (1) The ‘aggravated’ offence involves an additional (and ulterior) intention (or recklessness) to endanger a person’s life. (2) The ‘aggravated’ offence could be committed even if the defendant destroyed or damaged his own property whilst the offence simpliciter involves property...', '{"type": "case", "label": "HKSAR v Luk Kai Sing", "keywords": ["offence", "aggravated", "hksar", "luk", "kai", "sing"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
