insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chu_ting_ting', 'case', 'HKSAR v Chu Ting-ting', 'HKSAR v Chu Ting-ting See also HKSAR v Lai Kwun-biu (賴冠標) (Chinese Judgment) (unreported, HCMA 966/2006, 13 May 2008), per DHCJ M Poon (as M Poon J then was); and HKSAR v Chu Ting-ting (朱婷婷) [2017] 4 HKLRD 651, [2016] HKCU 2429 (Chinese Judgment); [2017] 4 HKLRD 666 (English Translation), per Albert Wong J. 24 Contrary to section 1(2) of the Criminal Damage Act 1971. The ‘simple’ criminal charge was section 1(1) of the Criminal Damage Act 1971. 0004853942.INDD 300 6/12/2020...', '{"type": "case", "label": "HKSAR v Chu Ting-ting", "keywords": ["hksar", "criminal", "chu", "ting-ting", "chinese", "judgment)"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
