insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:co_in_r_v_booth', 'case', 'CO. In R v Booth', 'CO. In R v Booth Destroying or damaging property …… (3) An offence committed under this section by destroying or damaging property by fire shall be charged as arson. As a result, destruction or damage by fire must be charged as ‘arson’ under the statutory regime set out in section 60(3) of the CO. In R v Booth, it was held that:-28 [The Criminal Damage Act 1971] abolishes the common law offence of arson, but replaces it with section 1(1) and (3). The requirement 25 R v...', '{"type": "case", "label": "CO. In R v Booth", "keywords": ["booth", "arson", "co", "destroying", "damaging", "property"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
