insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_lai_kam_fat', 'case', 'HKSAR v Lai Kam Fat', 'HKSAR v Lai Kam Fat Sentencing tariffs for trafficking in different types of dangerous drugs are a matter of judicial precedents and are not specified statutorily.6 [10-8] To determine whether something constitutes a ‘substance’ under the DDO usually requires expert evidence.7 [10-9] Scientific evidence is pertinent regarding the composition of substances alleged to be dangerous drugs. However, a lack of expert evidence will not necessarily be fatal. For instance, admissio...', '{"type": "case", "label": "HKSAR v Lai Kam Fat", "keywords": ["his", "evidence", "possession", "hksar", "lai", "kam"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
