insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_lambert', 'case', 'R v Lambert', 'R v Lambert If a person is invited for dinner to a friend’s home, he is not in possession of the objects in that home simply because he is there and knows that the objects are there. The objects are not in his physical custody and he has neither the intention nor the authority to exercise control over them. [10-11] In R v Lambert, 11 the House of Lords stated that possession is comprised of two elements: the ‘physical element’ and the ‘mental element’. As summarise...', '{"type": "case", "label": "R v Lambert", "keywords": ["element", "possession", "physical", "he", "objects", "are"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
