insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chui_chi_wa_anor', 'case', 'HKSAR v Chui Chi Wa & Anor', 'HKSAR v Chui Chi Wa & Anor As stated by the Court of Appeal:-29 We find ourselves at a total loss to understand what the Judge was trying to say to the jury but the impression the jury may have gained is, we accept, that a mistaken belief as to the contents of the bags could not be a defence as provided by s.47(2) of the Dangerous Drugs Ordinance (Cap.134). 26 R v James McNamara (1988) 87 Cr App R 246 at 250-251. 27 Searle v Randolph [1972] Crim LR 779. 28 HKSAR v Chui Chi Wa & A...', '{"type": "case", "label": "HKSAR v Chui Chi Wa & Anor", "keywords": ["chui", "chi", "wa", "hksar", "anor", "we"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
