insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_court_of_appeal_echoed_this_view_in_hksar_v_yeung_yiu_kin', 'case', 'The Court of Appeal echoed this view in HKSAR v Yeung Yiu Kin', 'The Court of Appeal echoed this view in HKSAR v Yeung Yiu Kin Criminal Law in Hong Kong 336 the road.38 The Court of Appeal echoed this view in HKSAR v Yeung Yiu Kin,39 in which Yeung VP expressly held that ‘a victim will not “fall from the sky”’40 and come from nowhere. Having said this, the Court of Appeal held that:-41 As a reasonable driver, the appellant of course should pay attention to the road conditions. Yet, this does not mean that he has presume there would be pedestrians jay-walking all the time.', '{"type": "case", "label": "The Court of Appeal echoed this view in HKSAR v Yeung Yiu Kin", "keywords": ["appeal", "yeung", "echoed", "view", "hksar", "yiu"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
