insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:mok_chi_ho_v_the_queen', 'case', 'Mok Chi Ho v The Queen', 'Mok Chi Ho v The Queen This case dealt with the meaning of ‘has with him’ in section 18 of the Firearms Act 1968 in England. 79 Mok Chi Ho v The Queen [1979] HKLR 118, [1979] HKCU 25. 80 HKSAR v Mok Yu Ming & Ors [2001] HKLRD (Yrbk) 312, [2001] HKCU 814. This case dealt with the meaning of ‘public place’ in section 147 of the Crimes Ordinance (Cap 200). The definition of ‘public place’ is largely similar to that in section 33 of the POO. 0004853945.INDD 361 6/11/2020 3:53:22 PM', '{"type": "case", "label": "Mok Chi Ho v The Queen", "keywords": ["mok", "chi", "ho", "queen", "case", "dealt"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
