insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:secretary_for_justice_v_cheng_ka_yee', 'case', 'Secretary for Justice v Cheng Ka Yee', 'Secretary for Justice v Cheng Ka Yee [13-15] However, in the recent decision of Secretary for Justice v Cheng Ka Yee, the Court of Final Appeal expressly left open the question of whether ‘a smartphone or a iPhone’ is a computer for the purposes of section 161.24 [13-16] As a practical matter, however, given the nature of computers, one should bear in mind the evidential difficulties that may arise in proving that a defendant was the very person engaged in the criminal act. In this regard,...', '{"type": "case", "label": "Secretary for Justice v Cheng Ka Yee", "keywords": ["computer", "secretary", "justice", "cheng", "ka", "yee"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
