insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:a_local_example_of_the_court_exercising_that_assessment_is_hksar_v_lam_yung_yung', 'case', 'A local example of the court exercising that assessment is HKSAR v Lam Yung Yung.46 In that case', 'A local example of the court exercising that assessment is HKSAR v Lam Yung Yung.46 In that case Criminal Law in Hong Kong 390 avoid the same. A local example of the court exercising that assessment is HKSAR v Lam Yung Yung.46 In that case, the defendant was charged with conspiracy to defraud. It was held that she had ample opportunity to seek help from her family, friends or even the police and therefore the threat was not unavoidable in spite her having taken evasive action. [14-23] Clearly, the defence of duress does not grant ‘immunity’ to the...', '{"type": "case", "label": "A local example of the court exercising that assessment is HKSAR v Lam Yung Yung.46 In that case", "keywords": ["yung", "defendant", "threat", "was", "local", "example"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
