insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_heath', 'case', 'R v Heath', 'R v Heath [14-28] In R v Heath,54 the defendant claimed that he had been compelled by threats of physical violence to collect a consignment of drugs which gave rise to his conviction. His defence of duress failed. Kennedy LJ held that the defendant was not entitled to rely on the threats as an excuse for subsequent criminal conduct as he had accepted in evidence that he was likely to be subjected to threats when associating with those exerting the threat. 3. Nece...', '{"type": "case", "label": "R v Heath", "keywords": ["duress", "he", "threats", "necessity", "heath", "defendant"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
