insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_lau_wai_keung', 'case', 'HKSAR v Lau Wai-keung', 'HKSAR v Lau Wai-keung … In a system governed by the rule of law, any such dispensing power requires great caution. It should not be used as a means of introducing major and controversial policy change. In re A was a case of highly exceptional facts, where an immediate decision was required. Tony’s condition is tragic but sadly not unfamiliar… [14-43] In the recent case of HKSAR v Lau Wai-keung ,75 the defendant was charged with one count of attempted bank robbery. At trial,...', '{"type": "case", "label": "HKSAR v Lau Wai-keung", "keywords": ["defendant", "was", "hksar", "lau", "wai-keung", "case"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
