insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:scottish_case_of_burns_v_hm_advocate', 'case', 'Scottish case of Burns v HM Advocate', 'Scottish case of Burns v HM Advocate Criminal Law in Hong Kong 408 [14-78] There is also a rule, often taken for granted, that if the defendant himself was the aggressor, he cannot plead self-defence. Yet, in R v Rashford,128 the court approved of and quoted from the Scottish case of Burns v HM Advocate:-129 It is not accurate to say that a person who kills someone in a quarrel which he himself started, by provoking it or entering into it willingly, cannot plead self defence if his victim...', '{"type": "case", "label": "Scottish case of Burns v HM Advocate", "keywords": ["case", "himself", "scottish", "burns", "hm", "advocate"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
