insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:as_lord_morris_explained_in_r_v_palmer', 'case', 'As Lord Morris explained in R v Palmer', 'As Lord Morris explained in R v Palmer Accordingly, self-defence is justifiable only when the wrong threatened or committed is of such a violent or imminent nature that immediate action is necessary to protect life and property. [14-80] Nevertheless, in the heat of the moment, fine judgments are not to be expected.133 As Lord Morris explained in R v Palmer:-134 If there has been attack so that defence is reasonably necessary it will be recognized that a person defending himself cannot weigh...', '{"type": "case", "label": "As Lord Morris explained in R v Palmer", "keywords": ["necessary", "only", "action", "lord", "morris", "explained"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
