insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_martin', 'case', 'R v Martin', 'R v Martin Defences 409 [14-81] In defining the ‘reasonable person’, only physical conditions (but not psychiatric conditions) can be taken into account. In R v Martin (Anthony Edward),135 the defendant, who shot the burglars, was convicted of manslaughter. It was held that he was not entitled to rely on evidence of psychiatrists as to his psychiatric conditions, and that only the physical characteristics of the defendant can be considered.136 7. Intoxication [14-...', '{"type": "case", "label": "R v Martin", "keywords": ["was", "intoxication", "martin", "only", "physical", "conditions"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
