insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:dpp_v_morgan_as_this', 'case', 'DPP v Morgan as this', 'DPP v Morgan as this 7.1 Specific intent crime and basic intent crime [14-83] Lord Simon of Glaisdale defined ‘crimes of basic intent’ in DPP v Morgan as this:-137 … those crimes whose definition expresses (or, more often, implies) a mens rea which does not go beyond the actus reus. The actus reus generally consists of an act and some consequence. The consequence may be very closely connected with the act or more remotely connected with it: but with a crime of basic intent...', '{"type": "case", "label": "DPP v Morgan as this", "keywords": ["intent", "crime", "basic", "act", "actus", "reus"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
