insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:dpp_v_morgan', 'case', 'DPP v Morgan', 'DPP v Morgan However, the consequence of the act involved in the actus reus is less immediate. The prosecution must prove that the accused foresaw the occurrence of physical harm to another person in circumstances unjustified by law as a probable (or possible and desired) consequence of his act, or that he was reckless as to whether or not such consequence would ensue. [14-85] Where the crime is one of ‘specific intent’, the prosecution must in general prove that th...', '{"type": "case", "label": "DPP v Morgan", "keywords": ["dpp", "consequence", "act", "morgan", "prosecution", "prove"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
