insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:lord_denning_stated_the_position_clearly_in_attorney_general_for_northern_irelan', 'case', 'Lord Denning stated the position clearly in Attorney General for Northern Ireland v Gallagher', 'Lord Denning stated the position clearly in Attorney General for Northern Ireland v Gallagher Lord Denning stated the position clearly in Attorney General for Northern Ireland v Gallagher:-149 If a man, whilst sane and sober, forms an intention to kill and makes preparation for it, knowing it is a wrong thing to do, and then gets himself drunk so as to give himself Dutch courage to do the killing, and whilst drunk carries out his intention, he cannot rely on this self-induced drunkenness as a defence to a charge of murder, nor even as reducing i...', '{"type": "case", "label": "Lord Denning stated the position clearly in Attorney General for Northern Ireland v Gallagher", "keywords": ["lord", "denning", "stated", "position", "clearly", "attorney"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
