insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:a_g_for_northern_ireland_v_gallagher', 'case', 'A-G for Northern Ireland v Gallagher', 'A-G for Northern Ireland v Gallagher It was held that if the defendant had the requisite mens rea prior to the involuntary intoxication , then the defence of involuntary intoxication would not be open to him. The absence of moral fault by a defendant did not suffice per se to negate the necessary mental element of the offence with which he was charged. 149 A-G for Northern Ireland v Gallagher (Patrick) [1963] AC 349 at 382, [1961] 3 All ER 299 at 314E. 150 See below at [14-102] to [14-104]...', '{"type": "case", "label": "A-G for Northern Ireland v Gallagher", "keywords": ["intoxication", "a-g", "northern", "ireland", "gallagher", "was"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
