insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:that_distinction_can_be_found_in_many_cases_in_r_v_beard', 'case', 'That distinction can be found in many cases. In R v Beard', 'That distinction can be found in many cases. In R v Beard [14-101] Nevertheless, in R v Stripp, 162 the defendant sustained a concussion because he was drunk, and committed a criminal act in a state of automatism that arose from his concussion, yet the Court of Appeal held that the defendant should still be able to rely on automatism. 7.3.2 Intoxication and insanity [14-102] The law has long drawn a distinction between intoxication and a disease of the mind induced by intoxicants. That distinction can be found...', '{"type": "case", "label": "That distinction can be found in many cases. In R v Beard", "keywords": ["distinction", "drunkenness", "found", "many", "cases", "beard"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
