insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:applying_dpp_v_majewski', 'case', 'Applying DPP v Majewski', 'Applying DPP v Majewski 7.3.3 Intoxication and mistaken consent [14-105] In the context of sexual offences (such as rape and sexual assault, which are basic intent crimes), it is long established that the jury cannot take into account the defendant’s self-induced intoxication in assessing whether he had the relevant mens rea, including the question of whether he believed that the complainant consented.168 [14-106] Applying DPP v Majewski ,169 if by virtue of the intoxication t...', '{"type": "case", "label": "Applying DPP v Majewski", "keywords": ["intoxication", "applying", "dpp", "majewski", "consent", "sexual"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
