insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_asmelash', 'case', 'R v Asmelash', 'R v Asmelash So she did not consent to sexual intercourse if, because of intoxication, she lost consciousness temporarily, as she would not be able to make the decision to consent; (d) Where the complainant was voluntarily intoxicated, but nevertheless remained capable of choosing whether or not to have sexual intercourse and indicated her consent to do so, this would not be rape. As a matter of practical reality and depending on the particular facts, before a compl...', '{"type": "case", "label": "R v Asmelash", "keywords": ["she", "consent", "sexual", "intercourse", "intoxication", "asmelash"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
