insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:court_of_appeal_in_hksar_v_liu_chun_yip', 'case', 'Court of Appeal in HKSAR v Liu Chun Yip', 'Court of Appeal in HKSAR v Liu Chun Yip Defences 419 responsibility must fail. Such a direction is incorrect because it fails to recognise that the abnormality of mind arising from a cause specified in the subsection and the effect of the drink may each play a part in impairing the defendant’s mental responsibility for the killing. [14-112] More recently, in R v Daniel,181 the Privy Council acknowledged the important principle that self-induced intoxication cannot avail a defendant ‘unless th...', '{"type": "case", "label": "Court of Appeal in HKSAR v Liu Chun Yip", "keywords": ["appeal", "hksar", "liu", "chun", "yip", "responsibility"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
