insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:this_should_not_be_conflated_with_agreements_in_contract_law_as_lord_bridge_warn', 'case', 'This should not be conflated with agreements in contract law. As Lord Bridge warned in R v Anderson', 'This should not be conflated with agreements in contract law. As Lord Bridge warned in R v Anderson 2.1 Actus reus 2.1.1 An agreement to commit an offence [15-5] Section 159A(1) of the CO requires the existence of an agreement, which is defined as an ‘agreement to do an unlawful act or a lawful act by unlawful means’. 2 This should not be conflated with agreements in contract law. As Lord Bridge warned in R v Anderson:-3 ... any number of persons may agree that a course of conduct shall be pursued without undertaking any contractual liability. The agr...', '{"type": "case", "label": "This should not be conflated with agreements in contract law. As Lord Bridge warned in R v Anderson", "keywords": ["anderson", "agreement", "course", "conduct", "agreed", "should"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
