insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_chan_keen', 'case', 'HKSAR v Chan Keen', 'HKSAR v Chan Keen In the recent decision in HKSAR v Chan Keen,16 Ribeiro and Cheung PJJ said:- However, in a case where the prosecution chooses to include some specific dishonest means in the indictment not as overt acts, but as agreed dishonest means forming part of the conspiratorial agreement indicted, those agreed dishonest means, together with the object or purpose of the conspiracy, would give the conspiracy its identity. If in a single count of conspiracy, more th...', '{"type": "case", "label": "HKSAR v Chan Keen", "keywords": ["dishonest", "means", "conspiracy", "are", "agreed", "alleged"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
