insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:hksar_v_tam_tung_kee_25', 'case', 'HKSAR v Tam Tung Kee.25', 'HKSAR v Tam Tung Kee.25 [15-17] Lord Griffiths modified Anderson slightly in R v Yip Chiu-Cheung:-22 The crime of conspiracy requires an agreement between two or more persons to commit an unlawful act with the intention of carrying it out. It is the intention to carry out the crime that constitutes the necessary mens rea for the offence. In Hong Kong, the formulations in both R v Anderson 23 and R v Yip Chiu-cheung24 have been endorsed in HKSAR v Tam Tung Kee.25 [15-18] The me...', '{"type": "case", "label": "HKSAR v Tam Tung Kee.25", "keywords": ["offence", "conspiracy", "commit", "hksar", "tam", "tung"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
