insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:as_lord_nicholls_in_r_v_saik_explains', 'case', 'As Lord Nicholls in R v Saik explains', 'As Lord Nicholls in R v Saik explains Its essential purpose is to ensure that strict liability and recklessness have no place in the offence of conspiracy.28 As Lord Nicholls in R v Saik explains:-29 Under this subsection conspiracy involves a third mental element: intention or knowledge that a fact or circumstance necessary for the commission of the substantive offence will exist. Take the offence of handling stolen goods. One of its ingredients is that the goods must have been stolen. Tha...', '{"type": "case", "label": "As Lord Nicholls in R v Saik explains", "keywords": ["offence", "lord", "nicholls", "fact", "saik", "explains"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
