insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:some_general_guidance_was_offered_in_r_v_gullefer_43_in_that_case', 'case', 'Some general guidance was offered in R v Gullefer.43 In that case', 'Some general guidance was offered in R v Gullefer.43 In that case Some general guidance was offered in R v Gullefer.43 In that case, the defendant climbed onto a greyhound racetrack to stop a race because the dog he had bet on was losing and he hoped to recover his stake. The stewards decided not to stop the race. He was convicted of attempted theft of the stake of £18 which he had wagered with a bookmaker. In upholding the conviction, Lord Lane CJ articulated the following test:-44 Thus the judge’s task is to decide...', '{"type": "case", "label": "Some general guidance was offered in R v Gullefer.43 In that case", "keywords": ["he", "was", "had", "gullefer", "case", "jury"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
