insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:the_defendant_in_r_v_jones_was_charged_with_attempted_murder_47_he_climbed_into_', 'case', 'The defendant in R v Jones was charged with attempted murder.47 He climbed into the victim', 'The defendant in R v Jones was charged with attempted murder.47 He climbed into the victim It considered, in an accurate paraphrase of the statutory test, ‘whether the available evidence, if accepted, could show that a defendant had done an act showing that he had actually tried to commit the offence in question, or whether he had only got ready or put himself in a position or equipped himself to do so’. Despite feeling the ‘gravest unease’, on the facts the court felt bound to conclude that the evidence was not sufficient in law to support a...', '{"type": "case", "label": "The defendant in R v Jones was charged with attempted murder.47 He climbed into the victim", "keywords": ["was", "he", "victim", "defendant", "had", "gun"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
