insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_dagnall', 'case', 'R v Dagnall', 'R v Dagnall As Professor Chris Clarkson has noted, courts generally find attempt only where there has been a confrontation with the victim (for sexual offences or offences against the person) or with property (for property offences). Nevertheless, this can produce harsh results. In R v Dagnall, 51 the defendant was convicted of attempted rape, even though all that he had done was approach the victim to tell her he wanted to have sex with her and push her against a...', '{"type": "case", "label": "R v Dagnall", "keywords": ["victim", "offences", "was", "her", "dagnall", "attempt"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
