insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_whybrow', 'case', 'R v Whybrow', 'R v Whybrow Criminal Law in Hong Kong 434 conspired. This is echoed in the statute itself, as section 159G(5) of the CO explicitly disapplies the offence to offences of aiding, abetting, counselling or procuring. 3.2 Mens rea [15-35] A defendant can only be guilty of attempting to commit an offence if he has the intention to do so. 54 Therefore, as succinctly put by Edmund Davies LJ55 in R v Easom, ‘it is implicit in the concept of an attempt that the person acting...', '{"type": "case", "label": "R v Whybrow", "keywords": ["offence", "whybrow", "mens", "rea", "do", "so"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
