insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_khan', 'case', 'R v Khan', 'R v Khan In R v Khan,59 which is concerned with the reckless element in rape, Russell LJ held that the mens rea for rape and attempted rape is the same:-60 The only difference between the two offences [rape and attempted rape] is that in rape sexual intercourse takes place whereas in attempted rape it does not, although there has to be some act which is more than preparatory to sexual intercourse. Considered in that way, the intent of the defendant is precisely...', '{"type": "case", "label": "R v Khan", "keywords": ["rape", "attempted", "same", "intercourse", "khan", "reckless"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
