insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:a_different_approach_was_adopted_in_r_v_pace_and_rogers', 'case', 'A different approach was adopted in R v Pace and Rogers', 'A different approach was adopted in R v Pace and Rogers The Court of Appeal reversed the trial judge’s ruling, holding that intention was required as to the missing element (here, the damage to the car), but not as to any other matters at issue. Therefore, recklessness as to the endangering of life was sufficient for liability. [15-39] From this case, commentators have extracted the ‘missing element’ test: any elements of the substantive offence that were ‘missing’ would need to have been intended by the def...', '{"type": "case", "label": "A different approach was adopted in R v Pace and Rogers", "keywords": ["was", "pace", "rogers", "missing", "different", "approach"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
