insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:judge_in_r_v_lau_sai_wai', 'case', 'Judge in R v Lau Sai Wai', 'Judge in R v Lau Sai Wai In HKSAR v Kan Chung-hung,71 the defendant was convicted of attempting to export unmanifested cargo under section 18(1)(b) of the Import and Export Ordinance. 72 Section 18(1)(b) is one of strict liability, subject to a statutory ‘reasonable diligence’ defence in section 18(2). DHCJ Gill held that the strict liability of the substantive offence is preserved in the attempt to commit the offence:-73 Was it the intention of the Legislature in enacting s.15...', '{"type": "case", "label": "Judge in R v Lau Sai Wai", "keywords": ["offence", "export", "was", "strict", "liability", "commit"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
