insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:as_it_was_put_in_the_high_court_of_australia_in_miller_v_the_queen', 'case', 'As it was put in the High Court of Australia in Miller v The Queen', 'As it was put in the High Court of Australia in Miller v The Queen 4.3 Joint enterprise [15-74] The common law has developed two forms of joint criminal enterprise - the basic and the extended versions. [15-75] Also called the ‘plain vanilla’ form of joint enterprise, this basic version involves the co-adventurers agreeing to carry out, and then executing, a planned crime. As it was put in the High Court of Australia in Miller v The Queen:-128 If the crime that is the object of the enterprise is committed while the agr...', '{"type": "case", "label": "As it was put in the High Court of Australia in Miller v The Queen", "keywords": ["enterprise", "joint", "two", "basic", "were", "was"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
