insert into casemap_documents (id, kind, label, document_text, metadata) values ('case:r_v_becerra', 'case', 'R v Becerra', 'R v Becerra Therefore, the old authorities on the ‘fundamental difference’ rule are likely to retain their relevance in this jurisdiction. (d) Withdrawal from the enterprise [15-99] The rules applicable to withdrawal from secondary liability remain complex. Pre-Jogee 183 cases suggest that a withdrawal is valid where it takes place before the principal commits the offence, and before the act of assistance by the accomplice is effective. In R v Becerra, in the words...', '{"type": "case", "label": "R v Becerra", "keywords": ["withdrawal", "becerra", "place", "before", "assistance", "change"]}'::jsonb) on conflict (id) do update set kind = excluded.kind, label = excluded.label, document_text = excluded.document_text, metadata = excluded.metadata;
